function SiteInfoSocialPage() {
  const [cfg, setCfg] = useState<SiteSocialConfig>(DEFAULT_SITE_SOCIAL);
  const isDirty = JSON.stringify(cfg) !== JSON.stringify(DEFAULT_SITE_SOCIAL);
  const upd = (key: keyof SiteSocialConfig, patch: Partial<SocialItem>) =>
    setCfg(prev => ({ ...prev, [key]: { ...prev[key], ...patch } }));

  const enabledCount = Object.values(cfg).filter(s => s.enabled).length;

  return (
    <div className="flex flex-col gap-5 pb-2">
      <SettingsCard icon={Globe} title="ช่องทางโซเชียลมีเดีย"
        desc={`เปิดใช้งานและใส่ลิงก์เต็มของแต่ละช่องทาง — ใช้งาน ${enabledCount} จาก ${SOCIAL_PLATFORMS.length} ช่องทาง`}>
        <div className="flex flex-col gap-2.5">
          {SOCIAL_PLATFORMS.map((p) => {
            const item = cfg[p.id];
            return (
              <div key={p.id} className={`flex items-center gap-3 p-2.5 rounded-xl border transition-all ${
                item.enabled ? "border-gray-200 bg-white" : "border-gray-100 bg-gray-50"
              }`}>
                <div className={`shrink-0 transition-opacity ${item.enabled ? "" : "opacity-40 grayscale"}`}>
                  <SocialBrandIcon platform={p.id} className="size-9" />
                </div>
                <div className="flex-1 min-w-0 grid grid-cols-[120px_1fr] items-center gap-3">
                  <span className={`${font} text-[13px] ${item.enabled ? "text-black" : "text-gray-400"}`} style={{ fontWeight: 500 }}>
                    {p.label}
                  </span>
                  <input value={item.url} placeholder={p.placeholder} disabled={!item.enabled}
                    onChange={(e) => upd(p.id, { url: e.target.value })}
                    className={`${font} h-9 px-2.5 rounded-md border border-gray-200 text-[13px] focus:outline-none focus:border-[#319754] focus:ring-2 focus:ring-[#319754]/10 bg-white transition-all disabled:bg-gray-50 disabled:text-gray-400`} />
                </div>
                <div className="shrink-0">
                  <ToggleSwitch checked={item.enabled} onChange={(v) => upd(p.id, { enabled: v })} />
                </div>
              </div>
            );
          })}
        </div>
        <SaveBar isDirty={isDirty} onReset={() => setCfg(DEFAULT_SITE_SOCIAL)} onSave={() => toast.success("บันทึก Social Media เรียบร้อย")} />
      </SettingsCard>
    </div>
  );
}

/* ============================================================
 * SHIPPING SETTINGS PAGE — อิง UI จากหน้าตั้งค่าร้านค้า (shop)
 * แต่เป็นมุมมอง "platform-wide" สำหรับ admin
 * ========================================================== */
interface ShippingCarrier {
  id: string;
  name: string;
  code: string;            // ตัวอักษรย่อสำหรับ fallback (เมื่อไม่มีรูปโลโก้)
  color: string;           // สี fallback (เมื่อไม่มีรูปโลโก้)
  logo?: string;           // path/URL ของรูปโลโก้ขนส่ง
  cod: boolean;            // capability — ขนส่งนี้รองรับ COD หรือไม่
  trackingUrl: string;     // โดเมนสำหรับติดตามพัสดุ
  enabled: boolean;        // master switch
}

// Catalog ของขนส่งที่ระบบรู้จัก — admin เลือกจาก list นี้ผ่าน "เพิ่มขนส่ง" modal
const CARRIER_CATALOG: ShippingCarrier[] = [
  { id: "thpost",    name: "ไปรษณีย์ไทย",       code: "TH",   color: "#f8201e", logo: imgThaipost,  cod: true,  trackingUrl: "track.thailandpost.co.th", enabled: true },
  { id: "kerry",     name: "Kerry Express",      code: "K",    color: "#ff6600", logo: imgKerryLogo, cod: true,  trackingUrl: "th.kerryexpress.com",       enabled: true },
  { id: "flash",     name: "Flash Express",      code: "F",    color: "#fdc70d", logo: imgFlashLogo, cod: true,  trackingUrl: "flashexpress.com",          enabled: true },
  { id: "jt",        name: "J&T Express",        code: "J&T",  color: "#d40511", logo: imgJtLogo,    cod: true,  trackingUrl: "jtexpress.co.th",           enabled: true },
  { id: "best",      name: "Best Express",       code: "B",    color: "#d6001c",                     cod: true,  trackingUrl: "best-inc.co.th",            enabled: true },
  { id: "ninjavan",  name: "Ninja Van",           code: "NJ",   color: "#c8102e",                     cod: true,  trackingUrl: "ninjavan.co",                enabled: true },
  { id: "scg",       name: "SCG Express",         code: "SCG",  color: "#1a472a",                     cod: false, trackingUrl: "scgyamato.co.th",            enabled: true },
  { id: "dhl",       name: "DHL Express",        code: "DHL",  color: "#ffcc00",                     cod: false, trackingUrl: "dhl.com/th-th",              enabled: true },
  { id: "lalamove",  name: "Lalamove",             code: "LM",   color: "#f16622",                     cod: true,  trackingUrl: "lalamove.com",                enabled: true },
  { id: "grab",      name: "Grab Express",        code: "G",    color: "#00b14f",                     cod: true,  trackingUrl: "grab.com",                    enabled: true },
  { id: "linethman", name: "Lineman",              code: "LN",   color: "#00C300",                     cod: true,  trackingUrl: "lineman.line.me",             enabled: true },
  { id: "shopeeexp", name: "Shopee Express",     code: "SE",   color: "#ee4d2d",                     cod: true,  trackingUrl: "spx.co.th",                   enabled: true },
];

const DEFAULT_PLATFORM_CARRIERS: ShippingCarrier[] = CARRIER_CATALOG.slice(0, 4);

/* --- Shop-style helpers (มิเรอร์จาก SettingsPage shop) --- */
function ShipStepperInput({ value, onChange, step = 50 }: {
  value: number; onChange: (v: number) => void; step?: number;
}) {
  return (
    <div className="bg-[#fafafa] h-12 rounded-full w-full flex items-center justify-between pl-6 pr-2 py-3">
      <input
        value={value}
        onChange={(e) => {
          const n = Number(e.target.value);
          if (!isNaN(n)) onChange(Math.max(0, n));
        }}
        className={`bg-transparent text-[14px] ${font} outline-none w-full tabular-nums`} />
      <div className="h-8 shrink-0 w-[92px] relative flex items-center rounded-full overflow-hidden">
        <div className="absolute left-1/2 -translate-x-1/2 top-1 h-6 w-px bg-[rgba(60,60,67,0.3)] rounded-lg" />
        <button onClick={() => onChange(Math.max(0, value - step))}
          className="flex-1 h-full bg-[rgba(116,116,128,0.08)] rounded-l-full flex items-center justify-center cursor-pointer hover:bg-[rgba(116,116,128,0.15)] transition-colors">
          <span className="text-[17px] text-black leading-none select-none">−</span>
        </button>
        <button onClick={() => onChange(value + step)}
          className="flex-1 h-full bg-[rgba(116,116,128,0.08)] rounded-r-full flex items-center justify-center cursor-pointer hover:bg-[rgba(116,116,128,0.15)] transition-colors">
          <span className="text-[17px] text-black leading-none select-none">+</span>
        </button>
      </div>
    </div>
  );
}

// แปลง hex เป็น rgba พร้อม alpha
function brandAlpha(hex: string, alpha: number): string {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return `rgba(${r}, ${g}, ${b}, ${alpha})`;
}

function ShipCarrierBadge({ carrier, size = 44 }: { carrier: ShippingCarrier; size?: number }) {
  const darkText = ["flash", "dhl"].includes(carrier.id);
  return (
    <div className="rounded-full flex items-center justify-center shrink-0 shadow-[inset_0_-2px_4px_rgba(0,0,0,0.15)]"
      style={{
        width: size,
        height: size,
        backgroundColor: carrier.color,
        color: darkText ? "#1a1a1a" : "#fff",
        fontSize: size * 0.32,
        fontWeight: 800,
        letterSpacing: carrier.code.length > 2 ? "-0.5px" : "0",
      }}>
      {carrier.code}
    </div>
  );
}

function ShipToggle({ enabled, onToggle }: { enabled: boolean; onToggle: () => void }) {
  return (
    <button onClick={onToggle}
      className={`w-16 h-7 rounded-full cursor-pointer transition-colors relative shrink-0 p-0.5 flex items-center ${enabled ? "bg-[#34c759]" : "bg-[rgba(60,60,67,0.3)]"}`}>
      <div className={`w-[39px] h-6 bg-white rounded-full shadow transition-transform ${enabled ? "translate-x-[22px]" : "translate-x-0"}`} />
    </button>
  );
}

function AddCarrierDialog({ open, existingIds, onClose, onAdd }: {
  open: boolean;
  existingIds: string[];
  onClose: () => void;
  onAdd: (c: ShippingCarrier) => void;
}) {
  const available = CARRIER_CATALOG.filter(c => !existingIds.includes(c.id));
  return (
    <Dialog open={open} onOpenChange={(v) => { if (!v) onClose(); }}>
      <DialogContent className="max-w-[560px] p-0 overflow-hidden">
        <DialogHeader className="bg-[#319754]/5 px-5 pt-4 pb-3 border-b border-[#319754]/10">
          <DialogTitle className={`${font} text-[16px]`} style={{ fontWeight: 600 }}>เพิ่มขนส่ง</DialogTitle>
          <DialogDescription className={`${font} text-[12px] text-gray-500`}>
            เลือกขนส่งจากรายการเพื่อเพิ่มเข้าแพลตฟอร์ม
          </DialogDescription>
        </DialogHeader>

        <div className="px-5 py-4 max-h-[60vh] overflow-y-auto flex flex-col gap-2">
          {available.length === 0 ? (
            <div className="text-center py-10 flex flex-col items-center gap-2 text-gray-400">
              <Truck className="size-8" strokeWidth={1.5} />
              <p className={`${font} text-[13px]`}>ขนส่งทั้งหมดถูกเพิ่มเข้าระบบแล้ว</p>
            </div>
          ) : (
            available.map((c) => (
              <div key={c.id} className="flex items-center gap-3 p-3 rounded-xl border border-gray-200 hover:border-[#319754]/40 hover:bg-[#319754]/5 transition-all">
                <ShipCarrierBadge carrier={c} size={40} />
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 flex-wrap">
                    <p className={`${font} text-[14px] text-black`} style={{ fontWeight: 600 }}>{c.name}</p>
                    {c.cod && (
                      <span className={`${font} inline-flex items-center gap-1 text-[10px] px-1.5 py-0.5 rounded-full bg-[#ff9500]/15 text-[#ff9500]`} style={{ fontWeight: 600 }}>
                        <ShieldCheck className="size-2.5" strokeWidth={2.4} />
                        COD
                      </span>
                    )}
                  </div>
                  <p className={`${font} text-[11px] text-gray-500 mt-0.5 truncate`}>🌐 {c.trackingUrl}</p>
                </div>
                <button onClick={() => onAdd(c)}
                  className={`${font} inline-flex items-center gap-1.5 h-8 px-3 rounded-full text-white text-[12px] cursor-pointer hover:opacity-90 transition-opacity shrink-0`}
                  style={{ backgroundColor: ADMIN_PRIMARY, fontWeight: 500 }}>
                  <Plus className="size-3" strokeWidth={2.4} />
                  เพิ่ม
                </button>
              </div>
            ))
          )}
        </div>

        <DialogFooter className="px-5 py-3 border-t border-gray-100 bg-white">
          <button onClick={onClose}
            className={`${font} h-9 px-5 rounded-full bg-gray-100 hover:bg-gray-200 text-gray-700 text-[13px] cursor-pointer transition-colors`}
            style={{ fontWeight: 500 }}>
            ปิด
          </button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

function SettingsShippingPage() {
  // 1) ค่าตั้งต้นแพลตฟอร์ม (defaults สำหรับร้านใหม่)
  const [freeShippingMin,  setFreeShippingMin]  = useState(500);
  const [baseShippingCost, setBaseShippingCost] = useState(35);
  const [defaultWeight,    setDefaultWeight]    = useState(500);

  // 2) Master carrier list
  const [carriers, setCarriers] = useState<ShippingCarrier[]>(DEFAULT_PLATFORM_CARRIERS);
  const [showAddDialog, setShowAddDialog] = useState(false);

  const updateCarrier = (id: string, patch: Partial<ShippingCarrier>) =>
    setCarriers((prev) => prev.map((c) => c.id === id ? { ...c, ...patch } : c));
  const deleteCarrier = (id: string) => {
    setCarriers((prev) => prev.filter((c) => c.id !== id));
    toast.success("ลบขนส่งออกจากแพลตฟอร์มแล้ว");
  };
  const addFromCatalog = (c: ShippingCarrier) => {
    setCarriers((prev) => [...prev, { ...c, enabled: true }]);
    toast.success(`เพิ่ม ${c.name} เข้าแพลตฟอร์มแล้ว`);
  };

  // 3) นโยบาย COD แพลตฟอร์ม
  const [codEnabled,   setCodEnabled]   = useState(true);
  const [codFee,       setCodFee]       = useState(20);
  const [codMaxAmount, setCodMaxAmount] = useState(50000);

  // 4) Master remote areas
  const [remoteEnabled, setRemoteEnabled] = useState(true);
  const [remoteFee,     setRemoteFee]     = useState(150);
  const [remoteAreas,   setRemoteAreas]   = useState("เกาะสมุย, เกาะพะงัน, เกาะเต่า, เกาะช้าง, เกาะลันตา, แม่ฮ่องสอน (อ.ปาย, อ.ปางมะผ้า)");

  const enabledCarrierCount = carriers.filter(c => c.enabled).length;

  return (
    <div className="flex flex-col gap-5 pb-2">
      {/* CARD 1: Platform defaults */}
      <div className="bg-white rounded-2xl shadow-[0_1px_4px_rgba(0,0,0,0.04)] p-5 flex flex-col gap-4">
        <div className="pb-3 border-b border-[#e8e8e8] flex items-center gap-2">
          <Settings className="size-4 text-[#319754]" strokeWidth={2.2} />
          <p className={`${font} text-[15px] text-black`} style={{ fontWeight: 500 }}>ค่าตั้งต้นแพลตฟอร์ม</p>
          <span className={`${font} ml-2 bg-[#319754]/10 text-[#287745] text-[10px] px-2 py-0.5 rounded-full`} style={{ fontWeight: 600 }}>
            Defaults
          </span>
        </div>
        <p className={`${font} text-[11px] text-gray-500 -mt-2`}>ค่าเริ่มต้นที่ร้านค้าใหม่จะได้รับ — แต่ละร้านยังปรับเองได้ในหน้าตั้งค่าของตน</p>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="flex flex-col gap-1.5">
            <label className={`${font} text-[12px] text-gray-500 flex items-center gap-1.5`}>
              <Package className="size-3 text-gray-400" strokeWidth={2.4} />
              ส่งฟรีเมื่อซื้อครบ (฿)
            </label>
            <ShipStepperInput value={freeShippingMin} onChange={setFreeShippingMin} />
            <p className={`${font} text-[10px] text-gray-400 pl-3`}>0 = ไม่มีเงื่อนไขส่งฟรี default</p>
          </div>
          <div className="flex flex-col gap-1.5">
            <label className={`${font} text-[12px] text-gray-500 flex items-center gap-1.5`}>
              <DollarSign className="size-3 text-gray-400" strokeWidth={2.4} />
              ค่าจัดส่งเริ่มต้น (฿)
            </label>
            <ShipStepperInput value={baseShippingCost} onChange={setBaseShippingCost} />
            <p className={`${font} text-[10px] text-gray-400 pl-3`}>ใช้เป็น fallback เมื่อร้านยังไม่ตั้งค่า</p>
          </div>
          <div className="flex flex-col gap-1.5">
            <label className={`${font} text-[12px] text-gray-500 flex items-center gap-1.5`}>
              <Truck className="size-3 text-gray-400" strokeWidth={2.4} />
              น้ำหนักเริ่มต้น (กรัม)
            </label>
            <ShipStepperInput value={defaultWeight} onChange={setDefaultWeight} />
            <p className={`${font} text-[10px] text-gray-400 pl-3`}>สำหรับสินค้าที่ยังไม่กรอกน้ำหนัก</p>
          </div>
        </div>
      </div>

      {/* CARD 2: Master carrier list */}
      <div className="bg-white rounded-2xl shadow-[0_1px_4px_rgba(0,0,0,0.04)] p-5 flex flex-col gap-4">
        <div className="pb-3 border-b border-[#e8e8e8] flex items-center justify-between gap-2 flex-wrap">
          <div className="flex items-center gap-2">
            <Truck className="size-4 text-[#319754]" strokeWidth={2.2} />
            <p className={`${font} text-[15px] text-black`} style={{ fontWeight: 500 }}>ขนส่งที่รองรับบนแพลตฟอร์ม</p>
            <span className={`${font} ml-2 bg-[#319754]/10 text-[#287745] text-[10px] px-2 py-0.5 rounded-full`} style={{ fontWeight: 600 }}>
              Master List
            </span>
          </div>
          <div className="flex items-center gap-3">
            <span className={`${font} text-[11px] text-gray-500`}>
              <span className="text-[#319754] tabular-nums" style={{ fontWeight: 600 }}>{enabledCarrierCount}</span>
              <span className="text-gray-400"> / {carriers.length} ขนส่ง</span>
            </span>
            <button onClick={() => setShowAddDialog(true)}
              className={`${font} inline-flex items-center gap-1.5 h-8 px-3 rounded-full text-white text-[12px] cursor-pointer hover:opacity-90 transition-opacity`}
              style={{ backgroundColor: ADMIN_PRIMARY, fontWeight: 500 }}>
              <Plus className="size-3" strokeWidth={2.4} />
              เพิ่มขนส่ง
            </button>
          </div>
        </div>
        <p className={`${font} text-[11px] text-gray-500 -mt-2`}>
          ปิดที่นี่ = ขนส่งนี้จะถูกซ่อนจากทุกร้าน · <span style={{ fontWeight: 600 }}>ราคาและระยะเวลาจัดส่ง</span> ร้านค้าเป็นผู้กำหนดเอง
        </p>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
          {carriers.map((c) => {
            return (
              <div key={c.id}
                className="relative rounded-2xl overflow-hidden border border-gray-200 shadow-[0_1px_3px_rgba(0,0,0,0.04)] transition-colors"
                style={{ backgroundColor: c.enabled ? c.color : "#9ca3af" }}>

                {/* HEADER — transparent, shows outer brand bg */}
                <div className="relative overflow-hidden">
                  {/* Truck illustration — inside header, behind content */}
                  {c.logo && (
                    <img src={c.logo} alt=""
                      className="absolute pointer-events-none select-none z-0 transition-all"
                      style={{
                        right: 8,
                        top: 8,
                        height: "100px",
                        width: "auto",
                        maxWidth: "210px",
                        objectFit: "contain",
                        objectPosition: "right top",
                        filter: c.enabled ? "none" : "grayscale(100%)",
                      }} />
                  )}
                  <div className="relative z-10 flex items-start gap-3 p-4 pr-4">
                    {/* Small logo circle — white bg with brand color text */}
                    <div className="size-12 rounded-full flex items-center justify-center shrink-0 shadow-[inset_0_-2px_4px_rgba(0,0,0,0.08)] bg-white transition-colors"
                      style={{ color: c.enabled ? c.color : "#9ca3af" }}>
                      <span className={`${fontBold} text-[14px]`} style={{ fontWeight: 800, letterSpacing: c.code.length > 2 ? "-0.5px" : "0" }}>
                        {c.code}
                      </span>
                    </div>
                    {/* Name + tracking URL */}
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 flex-wrap">
                        <h3 className={`${font} text-[18px] text-white`} style={{ fontWeight: 700 }}>{c.name}</h3>
                        {c.cod && (
                          <span className={`${font} inline-flex items-center gap-1 text-[10px] px-2 py-0.5 rounded-full bg-white text-black`} style={{ fontWeight: 600 }}>
                            <ShieldCheck className="size-2.5 text-[#319754]" strokeWidth={2.4} />
                            COD
                          </span>
                        )}
                      </div>
                      <p className={`${font} text-[12px] mt-0.5 flex items-center gap-1.5 text-white/85 leading-none`}>
                        <Globe className="size-3 shrink-0" strokeWidth={2.4} />
                        <span className="truncate">{c.trackingUrl || "ยังไม่ได้กรอก URL ติดตาม"}</span>
                      </p>
                    </div>
                  </div>
                </div>

                {/* BODY — white card with rounded all 4 corners */}
                <div className="relative z-10">
                  <div className="rounded-2xl p-4 flex flex-col gap-3 bg-white">
                    {/* Master toggle row */}
                    <div className="flex items-center justify-between gap-3 pb-3 border-b border-gray-200">
                      <span className={`${font} text-[13px] text-gray-800`} style={{ fontWeight: 600 }}>เปิดใช้งานขนส่งนี้</span>
                      <ShipToggle enabled={c.enabled} onToggle={() => updateCarrier(c.id, { enabled: !c.enabled })} />
                    </div>
                    {/* Tracking URL field */}
                    <div className="pr-32">
                      <label className={`${font} text-[11px] text-gray-600`}>เว็บไซต์ติดตามพัสดุ</label>
                      <input value={c.trackingUrl} placeholder="track.example.com" disabled={!c.enabled}
                        onChange={(e) => updateCarrier(c.id, { trackingUrl: e.target.value })}
                        onFocus={(e) => {
                          if (!c.enabled) return;
                          e.currentTarget.style.borderColor = c.color;
                          e.currentTarget.style.boxShadow = `0 0 0 3px ${brandAlpha(c.color, 0.2)}`;
                        }}
                        onBlur={(e) => {
                          e.currentTarget.style.borderColor = "#e5e7eb";
                          e.currentTarget.style.boxShadow = "none";
                        }}
                        className={`${font} bg-white h-10 w-full mt-1 rounded-full px-4 text-[13px] text-black outline-none border border-gray-200 transition-all disabled:bg-gray-50 disabled:cursor-not-allowed disabled:text-gray-500`} />
                      <p className={`${font} text-[10px] text-gray-500 pl-3 mt-1.5`}>
                        URL ที่ลูกค้าใช้ติดตามพัสดุ — เป็นค่ามาตรฐานของขนส่ง ทุกร้านใช้ URL เดียวกัน
                      </p>
                    </div>

                    {/* COD + Delete */}
                    <div className="flex items-center justify-between gap-3 flex-wrap pt-2 border-t border-gray-200">
                      <label className={`flex items-center gap-2 ${c.enabled ? "cursor-pointer" : "cursor-not-allowed"}`}>
                        <input type="checkbox" checked={c.cod} disabled={!c.enabled}
                          onChange={(e) => updateCarrier(c.id, { cod: e.target.checked })}
                          className="hidden" />
                        <span className={`size-[18px] rounded-full border-2 flex items-center justify-center transition-all shrink-0 ${
                          c.cod ? "border-transparent" : "border-gray-400 bg-white"
                        }`}
                          style={c.cod ? { backgroundColor: c.color } : {}}>
                          {c.cod && <Check className="size-2.5 text-white" strokeWidth={3} />}
                        </span>
                        <span className={`${font} text-[12px] text-gray-800`} style={{ fontWeight: 500 }}>รองรับเก็บเงินปลายทาง (COD)</span>
                      </label>
                      <button onClick={() => deleteCarrier(c.id)}
                        className={`${font} inline-flex items-center gap-1.5 h-8 px-3 rounded-full bg-white hover:bg-[#ff3b30]/10 text-[#ff3b30] text-[12px] cursor-pointer transition-colors border border-[#ff3b30]/20`}
                        style={{ fontWeight: 500 }}>
                        <Trash2 className="size-3" strokeWidth={2.4} />
                        ลบออกจากแพลตฟอร์ม
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* CARD 3: COD policy */}
      <div className="bg-white rounded-2xl shadow-[0_1px_4px_rgba(0,0,0,0.04)] p-5 flex flex-col gap-4">
        <div className="pb-3 border-b border-[#e8e8e8] flex items-center justify-between gap-2">
          <div className="flex items-center gap-3">
            <div className="size-10 rounded-2xl bg-[#ff9500]/10 flex items-center justify-center shrink-0">
              <DollarSign className="size-5 text-[#ff9500]" strokeWidth={2.2} />
            </div>
            <div>
              <div className="flex items-center gap-2">
                <p className={`${font} text-[15px] text-black`} style={{ fontWeight: 500 }}>นโยบายเก็บเงินปลายทาง (COD)</p>
                <span className={`${font} bg-[#ff9500]/10 text-[#ff9500] text-[10px] px-2 py-0.5 rounded-full`} style={{ fontWeight: 600 }}>Platform</span>
              </div>
              <p className={`${font} text-[11px] text-gray-500 mt-0.5`}>ปิดที่นี่ = ทุกร้านในแพลตฟอร์มไม่สามารถเปิด COD ได้</p>
            </div>
          </div>
          <ShipToggle enabled={codEnabled} onToggle={() => setCodEnabled(!codEnabled)} />
        </div>

        <AnimatePresence initial={false}>
          {codEnabled && (
            <motion.div
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: "auto" }}
              exit={{ opacity: 0, height: 0 }}
              transition={{ duration: 0.25 }}
              className="overflow-hidden">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div className="flex flex-col gap-1.5">
                  <label className={`${font} text-[12px] text-gray-500`}>ค่าธรรมเนียม COD แนะนำ (฿)</label>
                  <ShipStepperInput value={codFee} onChange={setCodFee} step={10} />
                  <p className={`${font} text-[10px] text-gray-400 pl-3`}>ค่า default — แต่ละร้านปรับเองได้</p>
                </div>
                <div className="flex flex-col gap-1.5">
                  <label className={`${font} text-[12px] text-gray-500`}>วงเงิน COD สูงสุดต่อออเดอร์ (฿)</label>
                  <ShipStepperInput value={codMaxAmount} onChange={setCodMaxAmount} step={5000} />
                  <p className={`${font} text-[10px] text-gray-400 pl-3`}>เพดานสูงสุดของแพลตฟอร์ม — ร้านปรับลงได้แต่ห้ามเกิน</p>
                </div>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </div>

      {/* CARD 4: Master remote areas */}
      <div className="bg-white rounded-2xl shadow-[0_1px_4px_rgba(0,0,0,0.04)] p-5 flex flex-col gap-4">
        <div className="pb-3 border-b border-[#e8e8e8] flex items-center justify-between gap-2">
          <div className="flex items-center gap-3">
            <div className="size-10 rounded-2xl bg-[#0088ff]/10 flex items-center justify-center shrink-0">
              <MapPin className="size-5 text-[#0088ff]" strokeWidth={2.2} />
            </div>
            <div>
              <div className="flex items-center gap-2">
                <p className={`${font} text-[15px] text-black`} style={{ fontWeight: 500 }}>พื้นที่ห่างไกล</p>
                <span className={`${font} bg-[#0088ff]/10 text-[#0088ff] text-[10px] px-2 py-0.5 rounded-full`} style={{ fontWeight: 600 }}>Master List</span>
              </div>
              <p className={`${font} text-[11px] text-gray-500 mt-0.5`}>รายการกลางที่ทุกร้านใช้ร่วมกัน — ร้านเปิด/ปิดฟีเจอร์ได้ แต่รายการพื้นที่บริหารจากที่นี่</p>
            </div>
          </div>
          <ShipToggle enabled={remoteEnabled} onToggle={() => setRemoteEnabled(!remoteEnabled)} />
        </div>

        <AnimatePresence initial={false}>
          {remoteEnabled && (
            <motion.div
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: "auto" }}
              exit={{ opacity: 0, height: 0 }}
              transition={{ duration: 0.25 }}
              className="overflow-hidden">
              <div className="flex flex-col gap-4">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="flex flex-col gap-1.5">
                    <label className={`${font} text-[12px] text-gray-500 flex items-center gap-1.5`}>
                      <DollarSign className="size-3 text-gray-400" strokeWidth={2.4} />
                      ค่าจัดส่งเหมาจ่ายแนะนำ (฿)
                    </label>
                    <ShipStepperInput value={remoteFee} onChange={setRemoteFee} />
                    <p className={`${font} text-[10px] text-gray-400 pl-3`}>ค่า default ที่ร้านจะ inherit — ร้านปรับเองได้</p>
                  </div>
                  <div className="bg-[#0088ff]/5 border border-[#0088ff]/20 rounded-xl p-4 flex items-start gap-2.5">
                    <AlertCircle className="size-4 text-[#0088ff] shrink-0 mt-0.5" strokeWidth={2.2} />
                    <div>
                      <p className={`${font} text-[12px] text-[#0066b8]`} style={{ fontWeight: 600 }}>วิธีคำนวณ</p>
                      <p className={`${font} text-[11px] text-gray-600 mt-0.5 leading-relaxed`}>
                        ค่าส่งจะถูก override เป็น <span style={{ fontWeight: 600 }}>฿{remoteFee.toLocaleString()}</span> ทันที เมื่อระบบตรวจพบที่อยู่ลูกค้าอยู่ในรายการนี้
                      </p>
                    </div>
                  </div>
                </div>

                <div className="flex flex-col gap-1.5">
                  <label className={`${font} text-[12px] text-gray-500 flex items-center gap-1.5`}>
                    <MapPin className="size-3 text-gray-400" strokeWidth={2.4} />
                    รายการพื้นที่ห่างไกล (master list)
                  </label>
                  <textarea
                    value={remoteAreas}
                    onChange={(e) => setRemoteAreas(e.target.value)}
                    placeholder="ระบุชื่ออำเภอ / เกาะ / จังหวัด คั่นด้วย , เช่น เกาะสมุย, เกาะพะงัน"
                    rows={3}
                    className={`${font} bg-[#fafafa] rounded-2xl px-5 py-3 text-[13px] outline-none focus:ring-2 focus:ring-[#319754]/30 focus:bg-white transition-all resize-none placeholder:text-[#a3a3a3]`}
                    style={{ fontWeight: 500 }} />
                  <p className={`${font} text-[10px] text-gray-400 pl-3`}>ระบบจะตรวจที่อยู่ลูกค้าตาม keyword ในรายการนี้ (case-insensitive) — ใช้ร่วมกันทุกร้านในแพลตฟอร์ม</p>
                </div>
              </div>
            </motion.div>
          )}
        </AnimatePresence>

        <SaveBar isDirty={true} onReset={() => {
          setFreeShippingMin(500); setBaseShippingCost(35); setDefaultWeight(500);
          setCarriers(DEFAULT_PLATFORM_CARRIERS);
          setCodEnabled(true); setCodFee(20); setCodMaxAmount(50000);
          setRemoteEnabled(true); setRemoteFee(150); setRemoteAreas("เกาะสมุย, เกาะพะงัน, เกาะเต่า, เกาะช้าง, เกาะลันตา, แม่ฮ่องสอน (อ.ปาย, อ.ปางมะผ้า)");
        }} onSave={() => toast.success("บันทึกตั้งค่าการจัดส่งแพลตฟอร์มเรียบร้อย")} />
      </div>

      <AddCarrierDialog
        open={showAddDialog}
        existingIds={carriers.map(c => c.id)}
        onClose={() => setShowAddDialog(false)}
        onAdd={(c) => addFromCatalog(c)}
      />
    </div>
  );
}

/* ============================================================
 * USER REGISTRY PAGE
 * ========================================================== */
interface UserRecord {
  id: string;
  username: string;
  email: string;
  name: string;          // ชื่อ-นามสกุล
  role: "customer" | "owner" | "admin";
  status: "active" | "banned" | "pending";
}

// Seeded users live in AuthContext now — admin and register share the same list.

const ROLE_META: Record<UserRecord["role"], { label: string; color: string; bg: string }> = {
  customer: { label: "ลูกค้า",          color: "#6b7280", bg: "#f3f4f6" },
  owner:    { label: "ร้านค้า",         color: "#287745", bg: "#319754" + "1f" },
  admin:    { label: "ผู้ดูแลระบบ",     color: "#1d4ed8", bg: "#3b82f6" + "1f" },
};

const STATUS_META: Record<UserRecord["status"], { label: string; color: string; bg: string }> = {
  active:  { label: "ใช้งาน",     color: "#287745", bg: "#319754" + "1a" },
  banned:  { label: "ถูกระงับ",   color: "#dc2626", bg: "#ff3b30" + "1a" },
  pending: { label: "รออนุมัติ",   color: "#b45309", bg: "#f59e0b" + "1a" },
};

function KpiCard({ icon: Icon, label, value, color }: { icon: any; label: string; value: number | string; color: string }) {
  return (
    <div className="bg-white rounded-2xl shadow-[0_1px_4px_rgba(0,0,0,0.04)] p-4 flex items-center gap-3">
      <div className="size-11 rounded-xl flex items-center justify-center shrink-0" style={{ backgroundColor: `${color}1a` }}>
        <Icon className="size-5" style={{ color }} strokeWidth={2.2} />
      </div>
      <div className="min-w-0 flex-1">
        <p className={`${font} text-[11px] text-gray-500`}>{label}</p>
        <p className={`${fontBold} text-[22px] text-black tabular-nums`} style={{ fontWeight: 700 }}>{value}</p>
      </div>
    </div>
  );
}

function FilterTabs({ value, options, onChange }: {
  value: string;
  options: { id: string; label: string; count?: number }[];
  onChange: (v: any) => void;
}) {
  return (
    <div className="inline-flex bg-gray-100 rounded-full p-1 flex-wrap">
      {options.map((t) => {
        const active = value === t.id;
        return (
          <button key={t.id} onClick={() => onChange(t.id)}
            className={`${font} inline-flex items-center gap-1.5 h-8 px-4 rounded-full text-[12px] cursor-pointer transition-all ${
              active ? "bg-white shadow-sm text-black" : "text-gray-500 hover:text-black"
            }`} style={{ fontWeight: 500 }}>
            {t.label}
            {t.count !== undefined && (
              <span className={`tabular-nums text-[10px] px-1.5 py-0.5 rounded-full ${active ? "bg-[#319754]/10 text-[#319754]" : "bg-gray-200 text-gray-500"}`} style={{ fontWeight: 600 }}>
                {t.count}
              </span>
            )}
          </button>
        );
      })}
    </div>
  );
}

function SearchInput({ value, onChange, placeholder }: { value: string; onChange: (v: string) => void; placeholder: string }) {
  return (
    <div className="relative flex-1 min-w-[200px]">
      <Search className="absolute left-3 top-1/2 -translate-y-1/2 size-4 text-gray-400" strokeWidth={2.2} />
      <input type="text" value={value} onChange={(e) => onChange(e.target.value)} placeholder={placeholder}
        className={`${font} w-full h-10 pl-10 pr-3 rounded-full border border-gray-200 text-[13px] outline-none focus:ring-2 focus:ring-[#319754]/30 focus:border-[#319754] transition-all bg-white`} />
    </div>
  );
}

function UserAvatar({ user, size = 36 }: { user: UserRecord; size?: number }) {
  const initial = user.name.charAt(0);
  const bg = ROLE_META[user.role].color;
  return (
    <div className="rounded-full flex items-center justify-center shrink-0 text-white"
      style={{ width: size, height: size, backgroundColor: bg, fontSize: size * 0.4 }}>
      <span className={`${fontBold}`} style={{ fontWeight: 700 }}>{initial}</span>
    </div>
  );
}

function UsersListPage() {
  const { t } = useLanguage();
  const { users, updateUserRole: ctxUpdateRole, updateUserStatus: ctxUpdateStatus, removeUser: ctxRemoveUser } = useAuth();
  const [filter, setFilter] = useState<UserRecord["role"] | "all">("all");
  const [search, setSearch] = useState("");
  const [editingId, setEditingId] = useState<string | null>(null);
  const [detailUser, setDetailUser] = useState<UserRecord | null>(null);
  // Persisted across detail-page open/close within the session — keyed by user.id
  // so admin approve/reject decisions survive back-then-reopen.
  const [subRolesById, setSubRolesById] = useState<Record<string, OwnerSubRoles>>({});

  const updateUserRole = (id: string, newRole: UserRecord["role"]) => {
    const u = users.find(x => x.id === id);
    if (!u) return;
    if (u.role === newRole) return;
    // Prevent removing the last admin in the system
    if (u.role === "admin" && newRole !== "admin") {
      const adminCount = users.filter(x => x.role === "admin").length;
      if (adminCount <= 1) {
        toast.error("ต้องมีแอดมินอย่างน้อย 1 คนในระบบ");
        return;
      }
    }
    ctxUpdateRole(id, newRole as DisplayRole);
    toast.success(`เปลี่ยน ${u.name} เป็น ${ROLE_META[newRole].label}`);
  };

  const stats = useMemo(() => ({
    total:    users.length,
    customer: users.filter(u => u.role === "customer").length,
    owner:    users.filter(u => u.role === "owner").length,
    admin:    users.filter(u => u.role === "admin").length,
  }), [users]);

  const filtered = users.filter((u) => {
    if (filter !== "all" && u.role !== filter) return false;
    if (search.trim()) {
      const q = search.toLowerCase();
      if (!u.name.toLowerCase().includes(q) && !u.username.toLowerCase().includes(q) && !u.email.toLowerCase().includes(q)) return false;
    }
    return true;
  });

  const deleteUser = (id: string) => {
    const u = users.find(x => x.id === id);
    if (!u) return;
    ctxRemoveUser(id);
    toast.success(`ลบ ${u.username} เรียบร้อย`);
  };

  const tabs: { id: UserRecord["role"] | "all"; label: string; count: number; Icon: any }[] = [
    { id: "all",      label: t("admin_users_tab_all")      || "ทั้งหมด", count: stats.total,    Icon: Users },
    { id: "customer", label: t("admin_users_tab_customer") || "ลูกค้า",  count: stats.customer, Icon: Users },
    { id: "owner",    label: t("admin_users_tab_owner")    || "ร้านค้า", count: stats.owner,    Icon: Store },
    { id: "admin",    label: t("admin_users_tab_admin")    || "แอดมิน",  count: stats.admin,    Icon: Shield },
  ];

  const pct = (n: number) => stats.total === 0 ? 0 : Math.round((n / stats.total) * 100);
  const kpiCards = [
    { label: t("admin_overview_total_users") || "ผู้ใช้ทั้งหมด", value: stats.total.toLocaleString(), subLabel: `${tabs.length - 1} บทบาทในระบบ`, accent: "#319754", Icon: Users },
    { label: t("admin_users_tab_customer")    || "ลูกค้า",        value: stats.customer.toLocaleString(), subLabel: `${pct(stats.customer)}% ของผู้ใช้`, accent: "#6b7280", Icon: Users },
    { label: t("admin_users_tab_owner")       || "ร้านค้า",       value: stats.owner.toLocaleString(),    subLabel: `${pct(stats.owner)}% ของผู้ใช้`,    accent: "#9747ff", Icon: Store },
    { label: t("admin_users_tab_admin")       || "แอดมิน",        value: stats.admin.toLocaleString(),    subLabel: `${pct(stats.admin)}% ของผู้ใช้`,    accent: "#3b82f6", Icon: Shield },
  ];

  if (detailUser) {
    const live = users.find((u) => u.id === detailUser.id) ?? detailUser;
    return <UserDetailPage
      key={detailUser.id}
      user={live}
      subRolesOverride={subRolesById[detailUser.id]}
      onSubRolesChange={(next) => setSubRolesById((prev) => ({ ...prev, [detailUser.id]: next }))}
      onBack={() => setDetailUser(null)}
      onDelete={() => { deleteUser(detailUser.id); setDetailUser(null); }}
      onUpdateStatus={(s) => {
        ctxUpdateStatus(detailUser.id, s as RegistryStatus);
        toast.success(s === "banned" ? `ระงับบัญชี ${detailUser.username} แล้ว` : s === "active" ? `ปลดระงับบัญชี ${detailUser.username} แล้ว` : `อัปเดตสถานะแล้ว`);
      }}
      onUpdateRole={(r) => updateUserRole(detailUser.id, r as UserRecord["role"])}
    />;
  }

  return (
    <div>
      <div className="flex items-center justify-between mb-6 flex-wrap gap-3">
        <div>
          <h2 className={`${font} text-[22px]`} style={{ fontWeight: 600 }}>{t("admin_users_page_title") || "จัดการผู้ใช้งาน"}</h2>
          <p className={`${font} text-[13px] text-gray-500 mt-0.5`}>{t("admin_users_page_subtitle") || "ดูและจัดการบัญชีผู้ใช้งานทั้งหมด"}</p>
        </div>
      </div>

      {/* KPI cards — same pattern as AdminOrdersContent */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-5">
        {kpiCards.map((s) => (
          <div key={s.label}
            className="group rounded-2xl p-5 transition-shadow hover:shadow-[0px_2px_12px_rgba(0,0,0,0.04)] relative overflow-hidden"
            style={{ backgroundColor: `${s.accent}0d` }}>
            <div className="relative">
              <div className="flex items-center justify-between">
                <p className={`${font} text-[12px] text-gray-500`}>{s.label}</p>
                <div className="size-9 rounded-xl flex items-center justify-center" style={{ backgroundColor: `${s.accent}1a` }}>
                  <s.Icon className="size-4" style={{ color: s.accent }} strokeWidth={2.4} />
                </div>
              </div>
              <p className={`${font} text-[26px] mt-3 tracking-tight tabular-nums`} style={{ fontWeight: 700, color: s.accent }}>
                <AnimatedValue value={s.value} />
              </p>
              <div className="flex items-center gap-1.5 mt-2">
                <span className={`${font} inline-flex items-center gap-1 text-[11px] px-2 py-0.5 rounded-md`}
                  style={{ backgroundColor: `${s.accent}15`, color: s.accent, fontWeight: 600 }}>
                  {s.subLabel}
                </span>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Filter pills + search — green theme */}
      <div className="bg-white rounded-full shadow-[0px_0px_6px_0px_rgba(0,0,0,0.08)] p-1 mb-3 flex items-center gap-2">
        <FilterTabPills tabs={tabs} active={filter} onChange={setFilter} pillId="adminUsersFilterPill" />
        <div className="flex items-center bg-[#f5f5f5] rounded-full pl-4 pr-1 h-[36px] flex-1 min-w-0 lg:flex-none lg:w-[280px] lg:ml-auto">
          <input value={search} onChange={(e) => setSearch(e.target.value)}
            placeholder={t("admin_users_search_ph") || "ค้นหาผู้ใช้ ชื่อ อีเมล"}
            className={`${font} flex-1 text-[13px] outline-none bg-transparent min-w-0`} />
          <button className="bg-[#319754] size-[28px] rounded-full cursor-pointer flex items-center justify-center shrink-0">
            <Search className="size-4 text-white" />
          </button>
        </div>
      </div>

      {/* Users table */}
      <div className="bg-white rounded-2xl shadow-[0_1px_4px_rgba(0,0,0,0.04)] p-5">
        <table className="w-full table-fixed">
          <colgroup>
            <col style={{ width: "5%" }} />
            <col style={{ width: "20%" }} />
            <col style={{ width: "22%" }} />
            <col style={{ width: "20%" }} />
            <col style={{ width: "14%" }} />
            <col style={{ width: "13%" }} />
            <col style={{ width: "6%" }} />
          </colgroup>
          <thead>
            <tr className={`${font} text-[12px] text-gray-500 border-b border-gray-100`}>
              <th className="text-left pb-3 pr-3" style={{ fontWeight: 500 }}>ID</th>
              <th className="text-left pb-3 pr-3" style={{ fontWeight: 500 }}>{t("admin_users_col_user") || "ผู้ใช้"}</th>
              <th className="text-left pb-3 pr-3" style={{ fontWeight: 500 }}>{t("settings_email") || "อีเมล"}</th>
              <th className="text-left pb-3 pr-3" style={{ fontWeight: 500 }}>ชื่อ-นามสกุล</th>
              <th className="text-left pb-3 pr-3" style={{ fontWeight: 500 }}>{t("admin_users_col_role") || "บทบาท"}</th>
              <th className="text-left pb-3 pr-3" style={{ fontWeight: 500 }}>{t("admin_users_col_status") || "สถานะ"}</th>
              <th className="text-center pb-3" style={{ fontWeight: 500 }}></th>
            </tr>
          </thead>
          <tbody>
            {filtered.length === 0 && (
              <tr><td colSpan={7} className={`py-12 text-center ${font} text-[13px] text-gray-400`}>{t("admin_users_no_users") || "ไม่พบผู้ใช้"}</td></tr>
            )}
            {filtered.map((u, idx) => {
              const role = ROLE_META[u.role];
              const status = STATUS_META[u.status];
              const isEditing = editingId === u.id;
              return (
                <tr key={u.id}
                  onClick={() => { if (!isEditing) setDetailUser(u); }}
                  className={`group/row border-b border-gray-50 last:border-b-0 transition-colors ${
                    isEditing ? "bg-[#fffbeb]" : "hover:bg-gray-50/50 cursor-pointer"
                  }`}
                  style={isEditing ? { boxShadow: "inset 3px 0 0 #f59e0b" } : {}}>
                  {/* ID */}
                  <td className="py-3 pr-3 align-middle">
                    <span className={`${font} text-[12px] text-gray-400 tabular-nums`}>{idx + 1}</span>
                  </td>
                  {/* User */}
                  <td className="py-3 pr-3 align-middle">
                    <div className="flex items-center gap-2.5 min-w-0">
                      <UserAvatar user={u} size={32} />
                      <div className="flex flex-col min-w-0">
                        <span className={`${font} text-[12px] text-black truncate`} style={{ fontWeight: 600 }} title={u.username}>{u.username}</span>
                        {isEditing && (
                          <span className={`${font} inline-flex items-center gap-1 text-[10px] text-[#b45309] mt-0.5`} style={{ fontWeight: 500 }}>
                            <Pencil className="size-2.5" strokeWidth={2.4} />
                            กำลังแก้ไข
                          </span>
                        )}
                      </div>
                    </div>
                  </td>
                  {/* Email */}
                  <td className="py-3 pr-3 align-middle">
                    <a href={`mailto:${u.email}`} className={`${font} text-[12px] text-[#3b82f6] hover:underline truncate block`} title={u.email}>{u.email}</a>
                  </td>
                  {/* Name */}
                  <td className="py-3 pr-3 align-middle">
                    <span className={`${font} text-[12px] text-gray-700 truncate block`} style={{ fontWeight: 500 }} title={u.name}>{u.name}</span>
                  </td>
                  {/* Role */}
                  <td className="py-3 pr-3 align-middle" onClick={(e) => { if (isEditing) e.stopPropagation(); }}>
                    {isEditing ? (
                      <Popover>
                        <PopoverTrigger asChild>
                          <button title="คลิกเพื่อเปลี่ยนบทบาท"
                            className={`${font} inline-flex items-center gap-1 text-[11px] px-2.5 py-1 rounded-full cursor-pointer hover:opacity-80 transition-opacity ring-2 ring-[#f59e0b]/40`}
                            style={{ backgroundColor: role.bg, color: role.color, fontWeight: 600 }}>
                            {role.label}
                            <ChevronDown className="size-3" strokeWidth={2.4} />
                          </button>
                        </PopoverTrigger>
                        <PopoverContent align="start" sideOffset={6} className="w-56 p-1.5 rounded-2xl border border-gray-100 bg-white shadow-[0_10px_28px_-8px_rgba(0,0,0,0.18)]">
                          <p className={`${font} text-[10px] text-gray-400 uppercase tracking-wide px-2 pt-1 pb-2`} style={{ fontWeight: 600 }}>
                            เปลี่ยนบทบาท
                          </p>
                          {(["customer", "owner", "admin"] as const).map((r) => {
                            const meta = ROLE_META[r];
                            const active = u.role === r;
                            return (
                              <button key={r} onClick={() => updateUserRole(u.id, r)}
                                className={`${font} w-full flex items-center justify-between gap-2 px-2.5 py-2 rounded-xl cursor-pointer transition-colors text-left ${active ? "bg-gray-50" : "hover:bg-gray-50"}`}>
                                <div className="flex items-center gap-2">
                                  <span className="size-2 rounded-full" style={{ backgroundColor: meta.color }} />
                                  <span className="text-[13px] text-black" style={{ fontWeight: active ? 600 : 500 }}>{meta.label}</span>
                                </div>
                                {active && <Check className="size-4 text-[#319754]" strokeWidth={2.5} />}
                              </button>
                            );
                          })}
                        </PopoverContent>
                      </Popover>
                    ) : (
                      <span className={`${font} inline-flex items-center text-[11px] px-2.5 py-1 rounded-full`}
                        style={{ backgroundColor: role.bg, color: role.color, fontWeight: 600 }}>
                        {role.label}
                      </span>
                    )}
                  </td>
                  {/* Status */}
                  <td className="py-3 pr-3 align-middle">
                    <span className={`${font} inline-flex items-center gap-1 text-[11px] px-2.5 py-1 rounded-full`}
                      style={{ backgroundColor: status.bg, color: status.color, fontWeight: 600 }}>
                      <Check className="size-2.5" strokeWidth={3} />
                      {status.label}
                    </span>
                  </td>
                  {/* Actions */}
                  <td className="py-3 text-center align-middle" onClick={(e) => e.stopPropagation()}>
                    <Popover>
                      <PopoverTrigger asChild>
                        <button className="size-7 rounded-full inline-flex items-center justify-center bg-[#787880]/15 hover:bg-[#787880]/25 text-gray-700 transition-colors cursor-pointer mx-auto data-[state=open]:bg-[#319754] data-[state=open]:text-white">
                          <MoreHorizontal className="size-4" />
                        </button>
                      </PopoverTrigger>
                      <PopoverContent align="end" sideOffset={6} className="w-[200px] p-1.5 rounded-2xl border border-gray-100 bg-white shadow-[0_10px_28px_-8px_rgba(0,0,0,0.18)]">
                        <button onClick={() => setDetailUser(u)}
                          className={`${font} w-full flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-gray-50 cursor-pointer text-left text-[13px] text-black`}>
                          <Eye className="size-3.5 text-[#319754]" strokeWidth={2.2} />
                          <span style={{ fontWeight: 500 }}>ดูรายละเอียด</span>
                        </button>
                        <button onClick={() => setEditingId(isEditing ? null : u.id)}
                          className={`${font} w-full flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-gray-50 cursor-pointer text-left text-[13px] text-black`}>
                          {isEditing
                            ? <><Check className="size-3.5 text-[#319754]" strokeWidth={2.4} /><span style={{ fontWeight: 500 }}>เสร็จสิ้น</span></>
                            : <><Pencil className="size-3.5 text-[#319754]" strokeWidth={2.2} /><span style={{ fontWeight: 500 }}>{t("admin_users_edit") || "แก้ไข"}</span></>}
                        </button>
                        <button onClick={() => toast.success(`รีเซตรหัสผ่าน ${u.username} เรียบร้อย`)}
                          className={`${font} w-full flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-gray-50 cursor-pointer text-left text-[13px] text-black`}>
                          <RotateCcw className="size-3.5 text-[#f59e0b]" strokeWidth={2.2} />
                          <span style={{ fontWeight: 500 }}>{t("admin_users_reset_pwd") || "รีเซ็ตรหัสผ่าน"}</span>
                        </button>
                        <div className="h-px bg-gray-100 my-1" />
                        <button onClick={() => { deleteUser(u.id); if (isEditing) setEditingId(null); }}
                          className={`${font} w-full flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-[#ff3b30]/10 cursor-pointer text-left text-[13px] text-[#dc2626]`}>
                          <Trash2 className="size-3.5" strokeWidth={2.2} />
                          <span style={{ fontWeight: 500 }}>{t("admin_users_delete") || "ลบ"}</span>
                        </button>
                      </PopoverContent>
                    </Popover>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>

        <p className={`${font} text-[11px] text-gray-400 mt-3`}>
          แสดง <span style={{ fontWeight: 600 }} className="text-[#319754]">{filtered.length}</span> จาก {users.length} ผู้ใช้
        </p>
      </div>
    </div>
  );
}

/* ============================================================
 * USER DETAIL — full-page admin view of a single user's profile,
 * recent activity, and security/access info. Mirrors the shop
 * application detail page pattern (green gradient hero + KPI strip
 * + grid body) but with role-aware fields/stats.
 * ========================================================== */

interface UserProfileMock {
  avatar?: string;
  phone: string;
  province: string;
  joinDate: string;     // human-readable
  lastLogin: string;
  twoFactor: boolean;
  notes?: string;
  // role-specific
  loginCount: number;
  // customer
  orderCount?: number;
  totalSpent?: number;
  wishlistCount?: number;
  reviewCount?: number;
  loyaltyTier?: "Bronze" | "Silver" | "Gold" | "Platinum";
  // owner
  shopId?: string;
  shopName?: string;
  productCount?: number;
  shopRevenue?: number;
  shopRating?: number;
  // admin
  permissionGroup?: string;
  lastAction?: string;
}

/** Synthesize a profile for a user. Deterministic from username so the same
 *  user always shows the same numbers across reloads. */
function mockUserProfile(u: UserRecord): UserProfileMock {
  // Simple djb2-style hash → pseudo-random but stable per username
  let h = 5381;
  for (let i = 0; i < u.username.length; i++) h = ((h << 5) + h) ^ u.username.charCodeAt(i);
  const n = (mod: number) => Math.abs(h % mod);
  const provinces = ["กรุงเทพมหานคร", "เชียงใหม่", "ภูเก็ต", "ขอนแก่น", "นครราชสีมา", "พะเยา", "เชียงราย", "ลำพูน", "ปทุมธานี"];
  const tiers: UserProfileMock["loyaltyTier"][] = ["Bronze", "Silver", "Gold", "Platinum"];

  const base: UserProfileMock = {
    phone: `0${(8 + n(2))}${String(n(99999999)).padStart(8, "0")}`.replace(/(\d{3})(\d{3})(\d{4})/, "$1-$2-$3").slice(0, 12),
    province: provinces[n(provinces.length)],
    joinDate: `${1 + n(28)} ${["ม.ค.", "ก.พ.", "มี.ค.", "เม.ย.", "พ.ค.", "มิ.ย.", "ก.ค.", "ส.ค.", "ก.ย.", "ต.ค.", "พ.ย.", "ธ.ค."][n(12)]} 256${7 + n(2)}`,
    lastLogin: ["เมื่อวาน", "วันนี้", "2 วันก่อน", "3 วันก่อน", "1 สัปดาห์ก่อน", "12 ชม. ที่แล้ว"][n(6)],
    twoFactor: n(3) === 0,
    loginCount: 8 + n(400),
  };

  if (u.role === "customer") {
    return {
      ...base,
      orderCount: 2 + n(48),
      totalSpent: 1500 + n(85000),
      wishlistCount: n(35),
      reviewCount: n(22),
      loyaltyTier: tiers[n(tiers.length)],
    };
  }
  if (u.role === "owner") {
    return {
      ...base,
      shopId: `s-${String(1 + n(8)).padStart(3, "0")}`,
      shopName: u.name.includes("METAHERB") || u.name.toLowerCase().includes("metaherb") ? "เมต้าเฮิร์บ" : `ร้าน${u.name}`,
      productCount: 5 + n(280),
      shopRevenue: 8000 + n(2_000_000),
      shopRating: 3.5 + (n(15) / 10),
    };
  }
  // admin
  const groups = ["Super Admin", "Content Editor", "Operations", "Finance Auditor"];
  const actions = ["อนุมัติร้านค้า s-006", "ลบรีวิว #r-2384", "อัปเดต Banner 'ปีใหม่ 2568'", "ระงับบัญชี u-2294", "ย้ายสิทธิ์เป็น Operations"];
  return {
    ...base,
    permissionGroup: groups[n(groups.length)],
    lastAction: actions[n(actions.length)],
  };
}

/* ===== Owner sub-roles ===== */
type SpecialRoleStatus = "none" | "pending" | "approved" | "rejected" | "revoked";
type SpecialRoleKey = "trial_brand" | "herbal_market";

interface SpecialRoleApp {
  status: SpecialRoleStatus;
  submittedAt?: string;
  approvedAt?: string;
  rejectedReason?: string;
  fields: { label: string; value: string; tabular?: boolean; fullWidth?: boolean }[];
  documents: { label: string; status: "uploaded" | "missing" }[];
}

interface OwnerSubRoles {
  trial_brand: SpecialRoleApp;
  herbal_market: SpecialRoleApp;
}

const SPECIAL_ROLE_META: Record<SpecialRoleKey, { label: string; icon: any; color: string; accent: string; tagline: string }> = {
  trial_brand:   { label: "แบรนด์ทดสอบ",     icon: FlaskConical, color: "#319754", accent: "#dcfce7", tagline: "ปลดล็อกระบบสินค้าทดลอง — ลงสินค้าให้ผู้ใช้จริงประเมินก่อนวางจำหน่าย" },
  herbal_market: { label: "Herbal Market",    icon: Beaker,       color: "#287745", accent: "#d1fae5", tagline: "ปลดล็อกตลาด B2B วัตถุดิบสมุนไพร — รับ RFQ และใบ PO จากระบบ Herbal ERP" },
};

const SPECIAL_STATUS_META: Record<SpecialRoleStatus, { label: string; bg: string; color: string; dot: string }> = {
  none:     { label: "ยังไม่ได้สมัคร",  bg: "#f3f4f6", color: "#4b5563", dot: "#6b7280" },
  pending:  { label: "รออนุมัติ",         bg: "#fef3c7", color: "#b45309", dot: "#f59e0b" },
  approved: { label: "อนุมัติแล้ว",       bg: "#dcfce7", color: "#287745", dot: "#319754" },
  rejected: { label: "ปฏิเสธ",           bg: "#fee2e2", color: "#dc2626", dot: "#ef4444" },
  revoked:  { label: "ถูกเพิกถอน",       bg: "#fce7f3", color: "#9d174d", dot: "#be185d" },
};

/** Synthesize sub-role applications for an owner — deterministic from user.username
 *  so reload + state mutations don't reshuffle the seed. Non-owners get null. */
function mockOwnerSubRoles(u: UserRecord, baseProfile: UserProfileMock): OwnerSubRoles | null {
  if (u.role !== "owner") return null;
  let h = 5381;
  for (let i = 0; i < u.username.length; i++) h = ((h << 5) + h) ^ u.username.charCodeAt(i);
  const n = (mod: number) => Math.abs(h % mod);
  const statuses: SpecialRoleStatus[] = ["none", "pending", "approved", "rejected"];

  // Pinned demo statuses for seed owners — guarantees both queues display all 4
  // statuses out of the box so admins can demo approve / reject / revoke flows.
  const pinned: Record<string, { trial: SpecialRoleStatus; market: SpecialRoleStatus }> = {
    metaherb_store: { trial: "approved", market: "approved" },
    organicthai:    { trial: "approved", market: "approved" },
    doithaihoney:   { trial: "pending",  market: "approved" },
    arunlab:        { trial: "approved", market: "pending"  },
    lungjoy:        { trial: "pending",  market: "rejected" },
    teahousebkk:    { trial: "rejected", market: "pending"  },
    lungsomsak:     { trial: "none",     market: "none"     },
  };
  const pin = pinned[u.username];
  const trialStatus: SpecialRoleStatus  = pin ? pin.trial  : statuses[n(statuses.length)];
  const marketStatus: SpecialRoleStatus = pin ? pin.market : statuses[(n(statuses.length) + 1) % statuses.length];

  const trialBrand: SpecialRoleApp = {
    status: trialStatus,
    submittedAt: trialStatus === "none" ? undefined : `${1 + n(28)} ${["ม.ค.","ก.พ.","มี.ค.","เม.ย.","พ.ค.","มิ.ย.","ก.ค.","ส.ค.","ก.ย.","ต.ค.","พ.ย.","ธ.ค."][n(12)]} 2569`,
    approvedAt: trialStatus === "approved" ? `${1 + n(28)} เม.ย. 2569` : undefined,
    rejectedReason: trialStatus === "rejected" ? "เอกสารใบจดแจ้งเครื่องสำอางหมดอายุ — กรุณาส่งใบใหม่" : undefined,
    fields: [
      { label: "ชื่อแบรนด์", value: baseProfile.shopName ?? u.name },
      { label: "เลขทะเบียนการค้า", value: `010556${String(n(1000000)).padStart(7, "0")}`, tabular: true },
      { label: "ผู้ติดต่อหลัก", value: u.name },
      { label: "อีเมล", value: u.email },
      { label: "เบอร์โทร", value: baseProfile.phone, tabular: true },
      { label: "เว็บไซต์", value: `https://${u.username}.brand.metaherb.co.th`, fullWidth: true },
    ],
    documents: [
      { label: "หนังสือรับรองบริษัท",     status: "uploaded" },
      { label: "ภพ.20 (ภาษีมูลค่าเพิ่ม)",   status: trialStatus === "pending" || trialStatus === "rejected" ? "missing" : "uploaded" },
      { label: "บัตรประชาชนผู้มีอำนาจ",    status: "uploaded" },
      { label: "หน้าสมุดบัญชีธนาคาร",       status: "uploaded" },
    ],
  };

  const marketCategories = ["ราก/หัว","ใบ","ดอก","เปลือก","ผล/เมล็ด","สมุนไพรรวม","น้ำมันสกัด","สารสกัดเข้มข้น"];
  const businessTypes = ["เกษตรกร / ฟาร์ม", "โรงสกัด", "โรงอบ / แปรรูป", "พ่อค้าส่ง / Trader", "OEM"];
  const herbalMarket: SpecialRoleApp = {
    status: marketStatus,
    submittedAt: marketStatus === "none" ? undefined : `${1 + n(28)} ${["ม.ค.","ก.พ.","มี.ค.","เม.ย.","พ.ค.","มิ.ย.","ก.ค.","ส.ค.","ก.ย.","ต.ค.","พ.ย.","ธ.ค."][n(12)]} 2569`,
    approvedAt: marketStatus === "approved" ? `${1 + n(28)} พ.ค. 2569` : undefined,
    rejectedReason: marketStatus === "rejected" ? "ใบรับรอง อย. ยังไม่ครบ — ต้องส่งเอกสารเพิ่มเติม" : undefined,
    fields: [
      { label: "ประเภทธุรกิจ", value: businessTypes[n(businessTypes.length)] },
      { label: "ชื่อบริษัท / แบรนด์", value: baseProfile.shopName ?? u.name },
      { label: "หมวดวัตถุดิบ", value: marketCategories[n(marketCategories.length)] + ", " + marketCategories[(n(marketCategories.length) + 1) % marketCategories.length] },
      { label: "MOQ (kg)", value: `${5 + n(50)}`, tabular: true },
      { label: "กำลังการผลิต/เดือน", value: `${100 + n(900)} kg`, tabular: true },
      { label: "พื้นที่จัดส่ง", value: "ทั่วประเทศไทย", fullWidth: true },
    ],
    documents: [
      { label: "หนังสือรับรองบริษัท",           status: "uploaded" },
      { label: "ใบรับรอง อย. (FDA)",            status: marketStatus === "rejected" ? "missing" : "uploaded" },
      { label: "GAP / Organic certification",   status: marketStatus === "pending" || marketStatus === "rejected" ? "missing" : "uploaded" },
      { label: "ใบรับรอง GMP / HACCP",          status: "uploaded" },
      { label: "หน้าสมุดบัญชีธนาคาร",            status: "uploaded" },
    ],
  };

  return { trial_brand: trialBrand, herbal_market: herbalMarket };
}

function UserDetailPage({ user, subRolesOverride, onSubRolesChange, onBack, onDelete, onUpdateStatus, onUpdateRole, initialTab = "general" }: {
  user: UserRecord;
  subRolesOverride?: OwnerSubRoles;
  onSubRolesChange: (next: OwnerSubRoles) => void;
  onBack: () => void;
  onDelete: () => void;
  onUpdateStatus: (status: UserRecord["status"]) => void;
  onUpdateRole: (role: UserRecord["role"]) => void;
  initialTab?: "general" | SpecialRoleKey;
}) {
  const role = ROLE_META[user.role];
  const status = STATUS_META[user.status];
  // Stable profile — only re-derive when the user IDENTITY changes.
  const p = useMemo(() => mockUserProfile(user), [user.id, user.username, user.role, user.status]);

  // Sub-role apps (owner only) — seeded once, persisted upstream by UsersListPage.
  // If the parent has a saved override (from a previous detail open), use it;
  // otherwise seed deterministically from mockOwnerSubRoles.
  const subRoles: OwnerSubRoles | null = useMemo(() => {
    if (user.role !== "owner") return null;
    return subRolesOverride ?? mockOwnerSubRoles(user, p) ?? null;
  }, [user.role, subRolesOverride, user, p]);

  const [tab, setTab] = useState<"general" | SpecialRoleKey>(initialTab);
  useEffect(() => { if (user.role !== "owner") setTab("general"); }, [user.role]);

  const mutateSubRole = (key: SpecialRoleKey, patch: Partial<SpecialRoleApp>) => {
    if (!subRoles) return;
    const next: OwnerSubRoles = { ...subRoles, [key]: { ...subRoles[key], ...patch } };
    onSubRolesChange(next);
  };

  // KPI strip — role-aware
  const fmt = (n: number) => n >= 1_000_000 ? `฿${(n / 1_000_000).toFixed(2)}M` : n >= 1000 ? `฿${(n / 1000).toFixed(1)}K` : `฿${n}`;
  const kpiItems = user.role === "customer" ? [
    { label: "ออเดอร์",   value: `${p.orderCount}`,     sub: "รวม" },
    { label: "ใช้จ่าย",   value: fmt(p.totalSpent ?? 0), sub: "" },
    { label: "Wishlist", value: `${p.wishlistCount}`,   sub: "ชิ้น" },
    { label: "รีวิว",     value: `${p.reviewCount}`,    sub: "ครั้ง" },
  ] : user.role === "owner" ? [
    { label: "สินค้า",    value: `${p.productCount}`,      sub: "รายการ" },
    { label: "รายได้",    value: fmt(p.shopRevenue ?? 0), sub: "รวม" },
    { label: "คะแนน",    value: p.shopRating !== undefined ? p.shopRating.toFixed(1) : "—", sub: "★" },
    { label: "ล็อกอิน",   value: `${p.loginCount}`,        sub: "ครั้ง" },
  ] : [
    { label: "ล็อกอิน",      value: `${p.loginCount}`, sub: "ครั้ง" },
    { label: "สิทธิ์",       value: p.permissionGroup ?? "—", sub: "" },
    { label: "2FA",         value: p.twoFactor ? "เปิด" : "ปิด", sub: "" },
    { label: "สมัครเมื่อ",   value: p.joinDate, sub: "" },
  ];

  return (
    <div>
      {/* Top row: back + action buttons */}
      <div className="flex items-center justify-between mb-5 gap-2 flex-wrap">
        <button onClick={onBack}
          className={`${font} inline-flex items-center gap-2 text-[12px] text-[#319754] bg-[#319754]/10 hover:bg-[#319754]/20 px-4 py-1.5 rounded-full cursor-pointer transition-colors`}
          style={{ fontWeight: 500 }}>
          <ChevronLeft className="size-3.5" strokeWidth={2.5} />
          กลับ
        </button>

        {/* Header actions — labeled pills, status-aware primary CTA */}
        <div className="flex items-center gap-2 shrink-0 flex-wrap">
          {/* Banned users → primary green "ปลดระงับ" CTA (parity with shop's เปิดร้านอีกครั้ง) */}
          {user.status === "banned" && (
            <button onClick={onUpdateStatus.bind(null, "active")}
              className={`${font} inline-flex items-center gap-2 h-10 px-5 rounded-full bg-[#319754] hover:bg-[#287745] text-white text-[13px] cursor-pointer transition-shadow shadow-[0_2px_8px_rgba(49,151,84,0.25)] hover:shadow-[0_4px_14px_rgba(49,151,84,0.35)]`}
              style={{ fontWeight: 600 }}>
              <RotateCcw className="size-4" strokeWidth={2.4} />
              ปลดระงับบัญชี
            </button>
          )}

          <button onClick={() => toast.success(`รีเซตรหัสผ่าน ${user.username} เรียบร้อย`)}
            className={`${font} inline-flex items-center gap-2 h-10 px-4 rounded-full bg-white border border-gray-200 hover:border-[#f59e0b] hover:text-[#b45309] text-gray-700 text-[13px] cursor-pointer transition-colors`}
            style={{ fontWeight: 500 }}>
            <RotateCcw className="size-4" strokeWidth={2.4} />
            รีเซ็ตรหัสผ่าน
          </button>
          <button onClick={() => toast.success(`ส่งอีเมลถึง ${user.email}`)}
            className={`${font} inline-flex items-center gap-2 h-10 px-4 rounded-full bg-white border border-gray-200 hover:border-[#319754] hover:text-[#319754] text-gray-700 text-[13px] cursor-pointer transition-colors`}
            style={{ fontWeight: 500 }}>
            <Mail className="size-4" strokeWidth={2.4} />
            ส่งอีเมล
          </button>

          {/* Active users → ระงับบัญชี shown as red-tinted secondary pill */}
          {user.status === "active" && (
            <button onClick={() => { onUpdateStatus("banned"); }}
              className={`${font} inline-flex items-center gap-2 h-10 px-4 rounded-full bg-white border border-gray-200 hover:border-[#dc2626] hover:text-[#dc2626] hover:bg-red-50/50 text-gray-700 text-[13px] cursor-pointer transition-colors`}
              style={{ fontWeight: 500 }}>
              <Ban className="size-4" strokeWidth={2.4} />
              ระงับบัญชี
            </button>
          )}

          {/* Kebab menu — overflow actions */}
          <Popover>
            <PopoverTrigger asChild>
              <button title="การกระทำเพิ่มเติม"
                className="size-10 rounded-full inline-flex items-center justify-center bg-white border border-gray-200 hover:border-[#319754] hover:text-[#319754] text-gray-600 transition-colors cursor-pointer data-[state=open]:bg-[#319754] data-[state=open]:text-white data-[state=open]:border-[#319754]"
                aria-label="การกระทำเพิ่มเติม">
                <MoreHorizontal className="size-4" />
              </button>
            </PopoverTrigger>
            <PopoverContent align="end" sideOffset={6} className="w-[260px] p-1.5 rounded-2xl border border-gray-100 bg-white shadow-[0_10px_28px_-8px_rgba(0,0,0,0.18)]">
              <p className={`${font} text-[10px] text-gray-400 uppercase tracking-wide px-2 pt-1 pb-2`} style={{ fontWeight: 600 }}>
                เปลี่ยนบทบาท
              </p>
              {(["customer", "owner", "admin"] as const).map((r) => {
                const meta = ROLE_META[r];
                const active = user.role === r;
                return (
                  <button key={r} onClick={() => onUpdateRole(r)}
                    className={`${font} w-full flex items-center justify-between gap-2 px-3 py-2 rounded-xl cursor-pointer transition-colors text-left ${active ? "bg-gray-50" : "hover:bg-gray-50"}`}>
                    <div className="flex items-center gap-2">
                      <span className="size-2 rounded-full" style={{ backgroundColor: meta.color }} />
                      <span className={`${font} text-[13px] text-black`} style={{ fontWeight: active ? 600 : 500 }}>{meta.label}</span>
                    </div>
                    {active && <Check className="size-4 text-[#319754]" strokeWidth={2.5} />}
                  </button>
                );
              })}
              <div className="h-px bg-gray-100 my-1 mx-2" />
              <button onClick={() => { if (confirm(`ลบผู้ใช้ ${user.username} ถาวร?`)) { onDelete(); } }}
                className={`${font} w-full flex items-center gap-3 px-3 py-2.5 rounded-xl hover:bg-[#ff3b30]/10 cursor-pointer text-left text-[13px] text-[#dc2626]`}>
                <Trash2 className="size-3.5" strokeWidth={2.4} />
                <span style={{ fontWeight: 500 }}>ลบผู้ใช้ถาวร</span>
              </button>
            </PopoverContent>
          </Popover>
        </div>
      </div>

      {/* ===== HERO CARD ===== */}
      <div className="bg-white rounded-2xl shadow-[0_1px_4px_rgba(0,0,0,0.04)] overflow-hidden mb-5">
        <div className="relative bg-gradient-to-br from-[#319754] via-[#287745] to-[#1d5b32] p-5 overflow-hidden">
          <Sparkles className="absolute -top-4 -right-4 size-32 text-white/5" strokeWidth={1.5} />
          <div className="relative flex items-start gap-4">
            {/* Avatar — circular, role-tinted (matches UserAvatar role coding) */}
            <div className="size-20 rounded-full shrink-0 flex items-center justify-center text-white border-2 border-white/30 shadow-[inset_0_-3px_8px_rgba(0,0,0,0.18)]"
              style={{ fontSize: 32, backgroundColor: role.color }}>
              <span className={`${fontBold}`} style={{ fontWeight: 800 }}>{user.name.charAt(0) || "?"}</span>
            </div>
            <div className="flex-1 min-w-0 pr-2">
              <p className={`${font} text-[10.5px] text-white/75 uppercase tracking-wider mb-1`} style={{ fontWeight: 600 }}>
                @{user.username} · {role.label}
              </p>
              <h2 className={`${font} text-[20px] text-white leading-tight`} style={{ fontWeight: 700 }}>
                {user.name}
              </h2>
              <p className={`${font} text-[12px] text-white/85 mt-1 leading-snug`}>
                เลขที่บัญชี {user.id.toUpperCase()} · สมัครเมื่อ {p.joinDate} · เข้าสู่ระบบล่าสุด {p.lastLogin}
              </p>
              <div className="mt-2 flex items-center gap-2 flex-wrap">
                <span className={`${font} inline-flex items-center gap-1.5 text-[11px] px-2.5 py-0.5 rounded-full bg-white/20 backdrop-blur-sm text-white`} style={{ fontWeight: 600 }}>
                  <span className="size-1.5 rounded-full bg-white" />
                  {status.label}
                </span>
                <span className={`${font} inline-flex items-center gap-1 text-[11px] px-2.5 py-0.5 rounded-full bg-white/15 backdrop-blur-sm text-white/95 max-w-[240px] min-w-0`} style={{ fontWeight: 500 }}>
                  <Mail className="size-3 shrink-0" strokeWidth={2.4} />
                  <span className="truncate">{user.email}</span>
                </span>
                <span className={`${font} inline-flex items-center gap-1 text-[11px] px-2.5 py-0.5 rounded-full bg-white/15 backdrop-blur-sm text-white/95`} style={{ fontWeight: 500 }}>
                  <Phone className="size-3" strokeWidth={2.4} /> {p.phone}
                </span>
              </div>
            </div>
          </div>

          {/* KPI strip */}
          <div className="relative flex flex-wrap items-center gap-x-5 gap-y-2 mt-4">
            {kpiItems.map((k, i, arr) => (
              <Fragment key={k.label}>
                <div className="inline-flex items-baseline gap-1.5">
                  <span className={`${font} text-[10px] text-white/65`} style={{ fontWeight: 500 }}>{k.label}</span>
                  <span className={`${font} text-[14px] text-white tabular-nums leading-none`} style={{ fontWeight: 700 }}>{k.value}</span>
                  {k.sub && <span className={`${font} text-[10px] text-white/65`}>{k.sub}</span>}
                </div>
                {i < arr.length - 1 && <span className="h-3 w-px bg-white/20" aria-hidden />}
              </Fragment>
            ))}
          </div>

          {/* Owner sub-role tabs — only render when role === "owner" */}
          {subRoles && (
            <div className="relative mt-4">
              <div className="inline-flex items-center gap-1 bg-white rounded-full p-1 shadow-[0_2px_8px_rgba(0,0,0,0.08)] max-w-full overflow-x-auto">
                {([
                  { key: "general" as const,        label: "ข้อมูลทั่วไป",   icon: UserCog },
                  { key: "trial_brand" as const,    label: SPECIAL_ROLE_META.trial_brand.label,    icon: SPECIAL_ROLE_META.trial_brand.icon,    statusKey: subRoles.trial_brand.status },
                  { key: "herbal_market" as const,  label: SPECIAL_ROLE_META.herbal_market.label,  icon: SPECIAL_ROLE_META.herbal_market.icon,  statusKey: subRoles.herbal_market.status },
                ]).map((t) => {
                  const isActive = tab === t.key;
                  const statusMeta = "statusKey" in t ? SPECIAL_STATUS_META[t.statusKey as SpecialRoleStatus] : undefined;
                  return (
                    <button key={t.key} onClick={() => setTab(t.key)}
                      className={`${font} relative inline-flex items-center gap-1.5 px-4 h-[34px] rounded-full text-[12.5px] cursor-pointer transition-colors whitespace-nowrap ${
                        isActive ? "text-white" : "text-gray-600 hover:text-gray-900"
                      }`}
                      style={{ fontWeight: isActive ? 700 : 500 }}>
                      {isActive && (
                        <motion.span layoutId="user-detail-tab"
                          className="absolute inset-0 rounded-full bg-gradient-to-br from-[#3fb56b] to-[#267a43] shadow-[0_2px_8px_rgba(49,151,84,0.35)]"
                          transition={{ type: "spring", stiffness: 380, damping: 30 }} />
                      )}
                      <t.icon className="size-3.5 relative z-10" strokeWidth={2.2} />
                      <span className="relative z-10">{t.label}</span>
                      {statusMeta && (
                        <span
                          className={`${font} relative z-10 size-2 rounded-full ${isActive ? "ring-1.5 ring-white" : ""}`}
                          style={{ backgroundColor: statusMeta.dot, boxShadow: isActive ? "0 0 0 1.5px #ffffff" : undefined }}
                          aria-label={statusMeta.label}
                          title={statusMeta.label}
                        />
                      )}
                    </button>
                  );
                })}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Body — tab-aware */}
      {subRoles && tab !== "general" ? (
        <SpecialRoleTabBody
          user={user}
          roleKey={tab}
          app={subRoles[tab]}
          onMutate={(patch) => mutateSubRole(tab, patch)}
        />
      ) : (
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-5 items-start">
        {/* Left/main — profile sections */}
        <div className="lg:col-span-2 space-y-5">
          <ShopAppSection icon={UserCog} title="ข้อมูลบัญชี">
            <ShopAppField label="ชื่อ-นามสกุล" value={user.name} />
            <ShopAppField label="ชื่อผู้ใช้" value={`@${user.username}`} />
            <ShopAppField label="อีเมล" value={user.email} icon={Mail} fullWidth />
            <ShopAppField label="เบอร์โทร" value={p.phone} icon={Phone} tabular />
            <ShopAppField label="จังหวัด" value={p.province} icon={MapPin} />
          </ShopAppSection>

          {/* Role-specific section */}
          {user.role === "customer" && (
            <ShopAppSection icon={ShoppingCart} title="พฤติกรรมการซื้อ">
              <ShopAppField label="ออเดอร์รวม" value={`${p.orderCount} ออเดอร์`} tabular />
              <ShopAppField label="ใช้จ่ายสะสม" value={fmt(p.totalSpent ?? 0)} tabular />
              <ShopAppField label="Wishlist" value={`${p.wishlistCount} รายการ`} tabular />
              <ShopAppField label="รีวิวที่เขียน" value={`${p.reviewCount} ครั้ง`} tabular />
              <ShopAppField label="ระดับสมาชิก" value={p.loyaltyTier ?? "Bronze"} />
            </ShopAppSection>
          )}

          {user.role === "owner" && (
            <ShopAppSection icon={Store} title="ข้อมูลร้านค้า">
              <ShopAppField label="ชื่อร้าน" value={p.shopName ?? "—"} />
              <ShopAppField label="รหัสร้าน" value={p.shopId?.toUpperCase() ?? "—"} />
              <ShopAppField label="จำนวนสินค้า" value={`${p.productCount} รายการ`} tabular />
              <ShopAppField label="รายได้รวม" value={fmt(p.shopRevenue ?? 0)} tabular />
              <ShopAppField label="คะแนนเฉลี่ย" value={p.shopRating !== undefined ? `${p.shopRating.toFixed(1)} ★` : "—"} tabular />
            </ShopAppSection>
          )}

          {user.role === "admin" && (
            <ShopAppSection icon={Shield} title="สิทธิ์และบทบาท">
              <ShopAppField label="กลุ่มสิทธิ์" value={p.permissionGroup ?? "—"} />
              <ShopAppField label="2FA" value={p.twoFactor ? "เปิดใช้งาน" : "ปิด"} />
              <ShopAppField label="กิจกรรมล่าสุด" value={p.lastAction ?? "—"} fullWidth />
            </ShopAppSection>
          )}

          <div className="bg-white rounded-2xl shadow-[0_1px_4px_rgba(0,0,0,0.04)] p-6">
            <div className="flex items-center gap-2 mb-3">
              <History className="size-4 text-[#319754]" strokeWidth={2.2} />
              <h4 className={`${font} text-[15px] text-black`} style={{ fontWeight: 600 }}>กิจกรรมล่าสุด</h4>
            </div>
            <div className="space-y-3">
              <ActivityRow time={p.lastLogin} text={`เข้าสู่ระบบจาก ${p.province}`} icon={Activity} color="#319754" />
              <ActivityRow time="3 วันก่อน" text={user.role === "customer" ? "ทำรายการสั่งซื้อ #ORD-20260204-03521" : user.role === "owner" ? "อัปเดตข้อมูลร้านค้า" : (p.lastAction ?? "เข้าระบบหลังบ้าน")} icon={Pencil} color="#3b82f6" />
              <ActivityRow time="2 สัปดาห์ก่อน" text="ยอมรับข้อกำหนดและเงื่อนไขฉบับปรับปรุง" icon={ShieldCheck} color="#9747ff" />
            </div>
          </div>
        </div>

        {/* Right column — security + quick actions */}
        <div className="lg:col-span-1 space-y-5">
          <div className="bg-white rounded-2xl shadow-[0_1px_4px_rgba(0,0,0,0.04)] p-6">
            <div className="flex items-center gap-2 mb-3">
              <Lock className="size-4 text-[#319754]" strokeWidth={2.2} />
              <h4 className={`${font} text-[15px] text-black`} style={{ fontWeight: 600 }}>ความปลอดภัย</h4>
            </div>
            <div className="space-y-3">
              <SecurityRow label="การยืนยัน 2 ขั้นตอน" value={p.twoFactor ? "เปิดใช้งาน" : "ยังไม่ได้เปิด"} ok={p.twoFactor} />
              <SecurityRow label="อีเมลยืนยัน" value="ยืนยันแล้ว" ok={true} />
              <SecurityRow label="รหัสผ่านล่าสุด" value="เปลี่ยน 47 วันก่อน" ok={true} />
              <SecurityRow label="จำนวนล็อกอิน" value={`${p.loginCount} ครั้ง`} ok={true} />
            </div>
          </div>

          <div className="bg-gradient-to-br from-[#319754]/[0.04] to-transparent border border-[#319754]/15 rounded-2xl p-5">
            <div className="flex items-center gap-2 mb-2">
              <Info className="size-4 text-[#319754]" strokeWidth={2.2} />
              <h4 className={`${font} text-[13px] text-[#1d5b32]`} style={{ fontWeight: 600 }}>หมายเหตุ</h4>
            </div>
            <p className={`${font} text-[12px] text-gray-600 leading-relaxed`}>
              บัญชีนี้สมัครเมื่อ {p.joinDate} · เคยล็อกอินทั้งหมด {p.loginCount} ครั้ง · ครั้งล่าสุด {p.lastLogin}
            </p>
          </div>
        </div>
      </div>
      )}
    </div>
  );
}

/* ===== SpecialRoleTabBody — view of a single sub-role application
 *  (trial brand or herbal market). Includes approve / reject / revoke / re-evaluate
 *  controls and a summary of the submitted form. */
function SpecialRoleTabBody({ user, roleKey, app, onMutate }: {
  user: UserRecord;
  roleKey: SpecialRoleKey;
  app: SpecialRoleApp;
  onMutate: (patch: Partial<SpecialRoleApp>) => void;
}) {
  const meta = SPECIAL_ROLE_META[roleKey];
  const statusMeta = SPECIAL_STATUS_META[app.status];
  const docsTotal = app.documents.length;
  const docsUploaded = app.documents.filter((d) => d.status === "uploaded").length;
  const docsMissing = docsTotal - docsUploaded;
  const RoleIcon = meta.icon;

  const todayTH = new Date().toLocaleDateString("th-TH", { day: "numeric", month: "short", year: "numeric" });

  const handleApprove = () => {
    onMutate({ status: "approved", approvedAt: todayTH, rejectedReason: undefined });
    toast.success(`อนุมัติ${meta.label}ของ ${user.username} แล้ว`);
  };
  const handleReject = () => {
    const reason = prompt("เหตุผลที่ปฏิเสธ (จะส่งไปยังผู้สมัคร):", app.rejectedReason ?? "");
    if (reason === null) return;
    const trimmed = reason.trim();
    if (!trimmed) {
      toast.error("กรุณาระบุเหตุผลที่ปฏิเสธ");
      return;
    }
    onMutate({ status: "rejected", rejectedReason: trimmed });
    toast.error(`ปฏิเสธ${meta.label}ของ ${user.username}`);
  };
  const handleRevoke = () => {
    if (!confirm(`เพิกถอนสิทธิ์ ${meta.label} ของ ${user.username}?\nสิทธิ์การใช้งานเมนู ${meta.label} จะถูกปิดทันที (ไม่กระทบบัญชีร้านค้าหลัก)`)) return;
    onMutate({ status: "revoked", rejectedReason: "ถูกเพิกถอนโดยแอดมิน" });
    toast.success(`เพิกถอนสิทธิ์ ${meta.label} แล้ว`);
  };
  const handleReevaluate = () => {
    onMutate({ status: "pending", rejectedReason: undefined });
    toast.success(`เปิดพิจารณา${meta.label}อีกครั้ง`);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-5 items-start">
      {/* Main column — status banner + actions + form summary */}
      <div className="lg:col-span-2 space-y-5">
        {/* Status banner */}
        <div className="bg-white rounded-2xl shadow-[0_1px_4px_rgba(0,0,0,0.04)] p-6">
          <div className="flex items-start gap-4 flex-wrap">
            <div className="size-12 rounded-2xl flex items-center justify-center shrink-0" style={{ backgroundColor: meta.accent }}>
              <RoleIcon className="size-6" style={{ color: meta.color }} strokeWidth={2.2} />
            </div>
            <div className="flex-1 min-w-[200px]">
              <div className="flex items-center gap-2 flex-wrap">
                <h3 className={`${font} text-[17px] text-black`} style={{ fontWeight: 700 }}>{meta.label}</h3>
                <span className={`${font} inline-flex items-center gap-1.5 text-[11px] px-2.5 py-1 rounded-full`}
                  style={{ backgroundColor: statusMeta.bg, color: statusMeta.color, fontWeight: 600 }}>
                  <span className="size-1.5 rounded-full" style={{ backgroundColor: statusMeta.dot }} />
                  {statusMeta.label}
                </span>
              </div>
              <p className={`${font} text-[12.5px] text-gray-600 leading-relaxed mt-1`}>{meta.tagline}</p>
              {app.submittedAt && (
                <p className={`${font} text-[11px] text-gray-500 mt-2`}>ยื่นใบสมัครเมื่อ {app.submittedAt}{app.approvedAt ? ` · อนุมัติเมื่อ ${app.approvedAt}` : ""}</p>
              )}
              {app.rejectedReason && (
                <div className={`${font} mt-3 text-[12px] bg-red-50 border border-red-100 text-[#dc2626] rounded-xl px-3 py-2 inline-flex items-start gap-2`}>
                  <AlertCircle className="size-3.5 mt-0.5 shrink-0" strokeWidth={2.4} />
                  <span><span style={{ fontWeight: 600 }}>เหตุผล: </span>{app.rejectedReason}</span>
                </div>
              )}
            </div>

            {/* Status-aware actions */}
            <div className="flex items-center gap-2 shrink-0 flex-wrap">
              {app.status === "pending" && (
                <>
                  <button onClick={handleReject}
                    className={`${font} inline-flex items-center gap-2 h-10 px-4 rounded-full bg-white border border-gray-200 hover:border-[#dc2626] hover:text-[#dc2626] hover:bg-red-50/50 text-gray-700 text-[13px] cursor-pointer transition-colors`}
                    style={{ fontWeight: 500 }}>
                    <X className="size-4" strokeWidth={2.4} /> ปฏิเสธ
                  </button>
                  <button onClick={handleApprove}
                    className={`${font} inline-flex items-center gap-2 h-10 px-5 rounded-full bg-[#319754] hover:bg-[#287745] text-white text-[13px] cursor-pointer transition-shadow shadow-[0_2px_8px_rgba(49,151,84,0.25)] hover:shadow-[0_4px_14px_rgba(49,151,84,0.35)]`}
                    style={{ fontWeight: 600 }}>
                    <Check className="size-4" strokeWidth={2.4} /> อนุมัติ
                  </button>
                </>
              )}
              {app.status === "approved" && (
                <button onClick={handleRevoke}
                  className={`${font} inline-flex items-center gap-2 h-10 px-4 rounded-full bg-white border border-gray-200 hover:border-[#dc2626] hover:text-[#dc2626] hover:bg-red-50/50 text-gray-700 text-[13px] cursor-pointer transition-colors`}
                  style={{ fontWeight: 500 }}>
                  <Ban className="size-4" strokeWidth={2.4} /> เพิกถอน
                </button>
              )}
              {(app.status === "rejected" || app.status === "revoked") && (
                <button onClick={handleReevaluate}
                  className={`${font} inline-flex items-center gap-2 h-10 px-5 rounded-full bg-[#319754] hover:bg-[#287745] text-white text-[13px] cursor-pointer transition-shadow shadow-[0_2px_8px_rgba(49,151,84,0.25)] hover:shadow-[0_4px_14px_rgba(49,151,84,0.35)]`}
                  style={{ fontWeight: 600 }}>
                  <RotateCcw className="size-4" strokeWidth={2.4} /> เปิดพิจารณาใหม่
                </button>
              )}
            </div>
          </div>
        </div>

        {/* Form summary */}
        {app.status !== "none" && (
          <ShopAppSection icon={FileText} title="ข้อมูลในใบสมัคร">
            {app.fields.map((f) => (
              <ShopAppField key={f.label} label={f.label} value={f.value} tabular={f.tabular} fullWidth={f.fullWidth} />
            ))}
          </ShopAppSection>
        )}
      </div>

      {/* Right column — documents (only if applied) */}
      <div className="lg:col-span-1 space-y-5">
        {app.status !== "none" ? (
          <div className="bg-white rounded-2xl shadow-[0_1px_4px_rgba(0,0,0,0.04)] p-6">
            <div className="flex items-center gap-2 mb-3">
              <Paperclip className="size-4 text-[#319754]" strokeWidth={2.2} />
              <h4 className={`${font} text-[15px] text-black flex-1`} style={{ fontWeight: 600 }}>เอกสารแนบ</h4>
              <span className={`${font} text-[11px] text-gray-500 tabular-nums`}>{docsUploaded}/{docsTotal} ไฟล์</span>
            </div>
            {docsMissing > 0 && (
              <div className={`${font} inline-flex items-center gap-1.5 text-[11px] px-2.5 py-1 rounded-full bg-amber-100 text-amber-800 mb-3`} style={{ fontWeight: 600 }}>
                <AlertCircle className="size-3" strokeWidth={2.4} /> ขาด {docsMissing} ไฟล์
              </div>
            )}
            <div className="space-y-2">
              {app.documents.map((d) => (
                <div key={d.label}
                  className={`flex items-center gap-3 px-3 py-2.5 rounded-xl border ${
                    d.status === "uploaded" ? "border-gray-100 bg-white" : "border-amber-100 bg-amber-50/40"
                  }`}>
                  <div className={`size-8 rounded-lg flex items-center justify-center shrink-0 ${
                    d.status === "uploaded" ? "bg-[#319754]/10" : "bg-amber-100"
                  }`}>
                    {d.status === "uploaded" ? (
                      <FileText className="size-4 text-[#319754]" strokeWidth={2.2} />
                    ) : (
                      <AlertCircle className="size-4 text-amber-700" strokeWidth={2.2} />
                    )}
                  </div>
                  <div className="min-w-0 flex-1">
                    <p className={`${font} text-[12.5px] text-black truncate`} style={{ fontWeight: 500 }}>{d.label}</p>
                    <p className={`${font} text-[10px] ${d.status === "uploaded" ? "text-[#319754]" : "text-amber-700"}`} style={{ fontWeight: 600 }}>
                      {d.status === "uploaded" ? "แนบมาแล้ว" : "ยังไม่ได้แนบ"}
                    </p>
                  </div>
                  {d.status === "uploaded" && (
                    <button onClick={() => toast.info(`ดาวน์โหลด ${d.label}`)}
                      className="size-7 rounded-full inline-flex items-center justify-center bg-gray-100 hover:bg-gray-200 text-gray-700 cursor-pointer transition-colors">
                      <Download className="size-3.5" strokeWidth={2.4} />
                    </button>
                  )}
                </div>
              ))}
            </div>
          </div>
        ) : (
          <div className="bg-white rounded-2xl shadow-[0_1px_4px_rgba(0,0,0,0.04)] p-6 text-center">
            <div className="size-12 rounded-2xl bg-gray-100 flex items-center justify-center mx-auto mb-3">
              <RoleIcon className="size-5 text-gray-400" strokeWidth={2.2} />
            </div>
            <p className={`${font} text-[13px] text-gray-600`} style={{ fontWeight: 500 }}>ผู้ใช้ยังไม่ได้สมัคร{meta.label}</p>
            <p className={`${font} text-[11px] text-gray-400 mt-1`}>เมื่อยื่นใบสมัครแล้ว แอดมินจะเห็นข้อมูลและกดอนุมัติได้ที่นี่</p>
          </div>
        )}
      </div>
    </div>
  );
}

function ActivityRow({ time, text, icon: Icon, color }: { time: string; text: string; icon: any; color: string }) {
  return (
    <div className="flex items-start gap-3">
      <div className="size-8 rounded-full flex items-center justify-center shrink-0" style={{ backgroundColor: `${color}15` }}>
        <Icon className="size-4" style={{ color }} strokeWidth={2.2} />
      </div>
      <div className="flex-1 min-w-0">
        <p className={`${font} text-[12.5px] text-black`} style={{ fontWeight: 500 }}>{text}</p>
        <p className={`${font} text-[10.5px] text-gray-500 mt-0.5`}>{time}</p>
      </div>
    </div>
  );
}

function SecurityRow({ label, value, ok }: { label: string; value: string; ok: boolean }) {
  return (
    <div className="flex items-center justify-between gap-3 pb-2 border-b border-gray-50 last:border-b-0 last:pb-0">
      <div className="flex items-center gap-2">
        {ok ? <ShieldCheck className="size-3.5 text-[#319754]" strokeWidth={2.4} /> : <AlertCircle className="size-3.5 text-amber-600" strokeWidth={2.4} />}
        <p className={`${font} text-[12px] text-gray-600`}>{label}</p>
      </div>
      <p className={`${font} text-[12px]`} style={{ fontWeight: 600, color: ok ? "#287745" : "#b45309" }}>{value}</p>
    </div>
  );
}

