function PermToggle({ checked, onChange, color, disabled }: { checked: boolean; onChange: () => void; color: string; disabled?: boolean }) {
  return (
    <button
      onClick={disabled ? undefined : onChange}
      disabled={disabled}
      className={`relative inline-flex h-[22px] w-[40px] rounded-full transition-all ${disabled ? "cursor-not-allowed opacity-50" : "cursor-pointer"}`}
      style={{ backgroundColor: checked ? color : "#e5e7eb" }}
      aria-pressed={checked}
    >
      <motion.span
        layout
        transition={{ type: "spring", stiffness: 500, damping: 32 }}
        className={`absolute top-[2px] size-[18px] rounded-full bg-white shadow-[0_1px_3px_rgba(0,0,0,0.2)]`}
        style={{ left: checked ? 20 : 2 }}
      />
    </button>
  );
}

function PermissionsPage() {
  const { t } = useLanguage();
  const [groups, setGroups] = useState<PermGroup[]>(INITIAL_PERM_GROUPS);

  // Editor draft state — changes only commit on Save
  const [draft, setDraft] = useState<PermGroup | null>(null);
  const [draftMode, setDraftMode] = useState<"add" | "edit" | null>(null);
  const [permSearch, setPermSearch] = useState("");

  const [confirm, setConfirm] = useState<{ kind: "group"; id: string; label: string } | null>(null);

  /* ----- group CRUD on the committed list ----- */
  const openAdd = () => {
    setDraft({
      id: `grp_${Date.now()}`,
      label: "", desc: "",
      icon: ShieldCheck, iconColor: PERM_COLOR_OPTIONS[0],
      permissions: [], enabled: true,
    });
    setDraftMode("add");
    setPermSearch("");
  };

  const openEditor = (id: string) => {
    const g = groups.find((x) => x.id === id);
    if (!g) return;
    setDraft({ ...g, permissions: [...g.permissions] });
    setDraftMode("edit");
    setPermSearch("");
  };

  const cancelDraft = () => { setDraft(null); setDraftMode(null); };

  const saveDraft = () => {
    if (!draft) return;
    if (!draft.label.trim()) {
      toast.error(t("admin_perm_err_name") || "กรุณาระบุชื่อกลุ่มสิทธิ");
      return;
    }
    if (draftMode === "add") {
      setGroups((prev) => [...prev, draft]);
      toast.success(t("admin_perm_group_created") || "เพิ่มกลุ่มสิทธิใหม่เรียบร้อย");
    } else {
      setGroups((prev) => prev.map((g) => g.id === draft.id ? draft : g));
      toast.success(t("admin_perm_group_saved") || "บันทึกกลุ่มสิทธิเรียบร้อย");
    }
    cancelDraft();
  };

  const toggleGroupEnabled = (id: string) => {
    const g = groups.find((x) => x.id === id);
    if (!g) return;
    setGroups((prev) => prev.map((x) => x.id === id ? { ...x, enabled: !x.enabled } : x));
    toast.success(g.enabled
      ? `${t("admin_perm_group_disabled") || "ปิดการใช้งานกลุ่ม"} "${g.label || "—"}"`
      : `${t("admin_perm_group_enabled") || "เปิดการใช้งานกลุ่ม"} "${g.label || "—"}"`);
  };

  const deleteGroup = (id: string) => {
    const g = groups.find((x) => x.id === id);
    if (!g) return;
    setGroups((prev) => prev.filter((x) => x.id !== id));
    if (draft?.id === id) cancelDraft();
    toast.success(`${t("admin_perm_group_deleted") || "ลบกลุ่ม"} "${g.label}"`);
  };

  /* ----- draft mutators ----- */
  const updateDraft = (patch: Partial<PermGroup>) => {
    setDraft((d) => d ? { ...d, ...patch } : d);
  };

  const toggleDraftEnabled = () => {
    setDraft((d) => d ? { ...d, enabled: !d.enabled } : d);
  };

  const togglePermInDraft = (permId: string) => {
    setDraft((d) => {
      if (!d) return d;
      const has = d.permissions.includes(permId);
      return { ...d, permissions: has ? d.permissions.filter((p) => p !== permId) : [...d.permissions, permId] };
    });
  };

  /* ============== EDITOR VIEW ============== */
  if (draft) {
    const g = draft;
    const GIcon = g.icon;
    const filteredAll = permSearch.trim()
      ? ALL_PERMISSIONS.filter((p) => {
          const q = permSearch.toLowerCase();
          return p.label.toLowerCase().includes(q) || p.desc.toLowerCase().includes(q) || p.category.toLowerCase().includes(q);
        })
      : ALL_PERMISSIONS;
    // Group filtered permissions by category for display
    const groupedByCategory = filteredAll.reduce<Record<string, SystemPermission[]>>((acc, p) => {
      (acc[p.category] ||= []).push(p);
      return acc;
    }, {});
    const enabledCount = g.permissions.length;
    const isAdd = draftMode === "add";
    const canSave = g.label.trim().length > 0;

    return (
      <div>
        {/* Back button — design system pattern (matches BannerForm/BlogForm) */}
        <div className="mb-5">
          <button onClick={cancelDraft}
            className={`${font} inline-flex items-center gap-2 text-[12px] text-[#319754] bg-[#319754]/10 hover:bg-[#319754]/20 px-4 py-1.5 rounded-full cursor-pointer transition-colors`}
            style={{ fontWeight: 500 }}>
            <ChevronLeft className="size-3.5" strokeWidth={2.5} />
            {t("admin_perm_back") || "กลับ"}
          </button>
        </div>

        {/* Header — same h2 + subtitle pattern as the rest of admin */}
        <div className="flex items-center justify-between mb-6 flex-wrap gap-3">
          <div>
            <h2 className={`${font} text-[22px]`} style={{ fontWeight: 600 }}>
              {isAdd ? (t("admin_perm_add_group") || "เพิ่มกลุ่มสิทธิใหม่") : (t("admin_perm_edit_group") || "แก้ไขกลุ่มสิทธิ")}
            </h2>
            <p className={`${font} text-[13px] text-gray-500 mt-0.5`}>
              {isAdd ? (t("admin_perm_group_form_desc") || "ตั้งชื่อ คำอธิบาย ไอคอน และสี") : `${t("admin_perm_editing") || "กำลังแก้ไข"} ${g.label || "—"}`}
            </p>
          </div>
          <div className="flex items-center gap-2">
            <button onClick={cancelDraft}
              className={`${font} inline-flex items-center gap-1.5 text-[13px] text-gray-700 bg-white border border-gray-200 hover:border-gray-300 hover:bg-gray-50 px-5 h-[36px] rounded-full cursor-pointer transition-colors`}
              style={{ fontWeight: 500 }}>
              {t("admin_perm_cancel") || "ยกเลิก"}
            </button>
            <motion.button whileTap={{ scale: 0.96 }} whileHover={canSave ? { scale: 1.03 } : undefined}
              disabled={!canSave}
              onClick={saveDraft}
              className={`${font} inline-flex items-center gap-2 text-[13px] text-white px-5 h-[36px] rounded-full transition-colors shadow-[0_2px_8px_rgba(49,151,84,0.25)] ${canSave ? "cursor-pointer" : "opacity-50 cursor-not-allowed"}`}
              style={{ backgroundColor: ADMIN_PRIMARY, fontWeight: 500 }}>
              <Check className="size-4" strokeWidth={2.4} />
              {t("admin_perm_save") || "บันทึก"}
            </motion.button>
          </div>
        </div>

        <div className="flex flex-col lg:flex-row gap-4">
          {/* ===== LEFT: Group info ===== */}
          <div className="lg:w-[360px] bg-white rounded-2xl shadow-[0_1px_4px_rgba(0,0,0,0.04)] p-4 sm:p-5 flex flex-col gap-4 lg:sticky lg:top-4 lg:self-start">
            <div className="flex items-center gap-2">
              <Folder className="size-4 text-[#319754]" strokeWidth={2.4} />
              <p className={`${font} text-[14px] text-black`} style={{ fontWeight: 600 }}>
                {t("admin_perm_group_info") || "ข้อมูลกลุ่มสิทธิ"}
              </p>
            </div>

            {/* Preview */}
            <div className="bg-gray-50 rounded-xl p-3 flex items-center gap-3">
              <div className="size-12 rounded-xl flex items-center justify-center shrink-0" style={{ backgroundColor: `${g.iconColor}1a` }}>
                <GIcon className="size-5" style={{ color: g.iconColor }} strokeWidth={2.2} />
              </div>
              <div className="min-w-0 flex-1">
                <p className={`${font} text-[14px] text-black truncate`} style={{ fontWeight: 600 }}>
                  {g.label || (t("admin_perm_group_name_ph") || "ชื่อกลุ่มสิทธิ")}
                </p>
                <p className={`${font} text-[11px] text-gray-500 truncate`}>
                  {g.desc || (t("admin_perm_group_desc_ph") || "คำอธิบาย")}
                </p>
              </div>
            </div>

            {/* Name */}
            <div className="flex flex-col gap-1.5">
              <label className={`${font} text-[12px] text-gray-500`}>{t("admin_perm_group_name") || "ชื่อกลุ่มสิทธิ"} <span className="text-[#ff3b30]">*</span></label>
              <input type="text" value={g.label} onChange={(e) => updateDraft({ label: e.target.value })}
                placeholder={t("admin_perm_group_name_ph") || "เช่น การเงิน, รายงาน"}
                className={`${font} h-10 px-3 rounded-xl border border-gray-200 text-[13px] outline-none focus:ring-2 focus:ring-[#319754]/30 focus:border-[#319754]`} />
            </div>

            {/* Desc */}
            <div className="flex flex-col gap-1.5">
              <label className={`${font} text-[12px] text-gray-500`}>{t("admin_perm_group_desc") || "คำอธิบาย"}</label>
              <textarea value={g.desc} onChange={(e) => updateDraft({ desc: e.target.value })} rows={2}
                placeholder={t("admin_perm_group_desc_ph") || "อธิบายว่ากลุ่มนี้เกี่ยวข้องกับอะไร"}
                className={`${font} px-3 py-2 rounded-xl border border-gray-200 text-[13px] outline-none focus:ring-2 focus:ring-[#319754]/30 focus:border-[#319754] resize-none`} />
            </div>

            {/* Icon picker */}
            <div className="flex flex-col gap-1.5">
              <label className={`${font} text-[12px] text-gray-500`}>{t("admin_perm_group_icon") || "ไอคอน"}</label>
              <div className="grid grid-cols-8 gap-1.5">
                {PERM_ICON_OPTIONS.map((o) => {
                  const OI = o.icon;
                  const active = g.icon === o.icon;
                  return (
                    <button key={o.id} onClick={() => updateDraft({ icon: o.icon })}
                      className={`size-9 rounded-lg flex items-center justify-center cursor-pointer transition-all ${active ? "" : "bg-gray-50 hover:bg-gray-100"}`}
                      style={active ? { backgroundColor: `${g.iconColor}1a`, boxShadow: `0 0 0 2px ${g.iconColor}` } : {}}>
                      <OI className="size-4" style={{ color: active ? g.iconColor : "#6b7280" }} strokeWidth={2.2} />
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Color picker */}
            <div className="flex flex-col gap-1.5">
              <label className={`${font} text-[12px] text-gray-500`}>{t("admin_perm_group_color") || "สี"}</label>
              <div className="flex gap-2 flex-wrap">
                {PERM_COLOR_OPTIONS.map((c) => (
                  <button key={c} onClick={() => updateDraft({ iconColor: c })}
                    className={`size-7 rounded-full cursor-pointer transition-all ${g.iconColor === c ? "ring-2 ring-offset-2" : ""}`}
                    style={{ backgroundColor: c, "--tw-ring-color": c } as any} />
                ))}
              </div>
            </div>

            <div className="h-px bg-gray-100" />

            {/* Enable / disable */}
            <div className="flex items-center justify-between gap-3">
              <div className="flex items-center gap-2 min-w-0">
                {g.enabled
                  ? <Eye className="size-4 text-[#319754]" strokeWidth={2.4} />
                  : <EyeOff className="size-4 text-gray-400" strokeWidth={2.4} />}
                <div>
                  <p className={`${font} text-[13px] text-black`} style={{ fontWeight: 600 }}>
                    {t("admin_perm_group_status") || "สถานะการใช้งานกลุ่ม"}
                  </p>
                  <p className={`${font} text-[11px] text-gray-500`}>
                    {g.enabled ? (t("admin_perm_enabled") || "เปิดใช้งาน") : (t("admin_perm_disabled") || "ปิดใช้งาน")}
                  </p>
                </div>
              </div>
              <PermToggle checked={g.enabled} onChange={toggleDraftEnabled} color="#319754" />
            </div>
          </div>

          {/* ===== RIGHT: System permission list with toggles ===== */}
          <div className="flex-1 bg-white rounded-2xl shadow-[0_1px_4px_rgba(0,0,0,0.04)] flex flex-col">
            {/* Header */}
            <div className="p-4 sm:p-5 flex flex-wrap items-center gap-3 border-b border-gray-100">
              <div className="flex items-center gap-2 flex-1 min-w-[200px]">
                <ShieldCheck className="size-4 text-[#319754]" strokeWidth={2.4} />
                <p className={`${font} text-[14px] text-black`} style={{ fontWeight: 600 }}>
                  {t("admin_perm_list_in_group") || "รายการสิทธิ"}
                </p>
                <span className={`${font} inline-flex items-center text-[11px] px-2 py-0.5 rounded-full bg-gray-100 text-gray-600`} style={{ fontWeight: 600 }}>
                  {enabledCount}/{ALL_PERMISSIONS.length}
                </span>
              </div>
              {/* Search */}
              <div className="relative w-full sm:w-[300px]">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 size-4 text-gray-400" strokeWidth={2.2} />
                <input type="text" value={permSearch} onChange={(e) => setPermSearch(e.target.value)}
                  placeholder={t("admin_perm_search_perm_ph") || "ค้นหารายการสิทธิ"}
                  className={`${font} w-full h-9 pl-10 pr-3 rounded-full border border-gray-200 text-[13px] outline-none focus:ring-2 focus:ring-[#319754]/30 focus:border-[#319754] transition-all bg-white`} />
              </div>
            </div>

            {/* List grouped by category */}
            {filteredAll.length === 0 ? (
              <div className="px-4 py-12 text-center flex flex-col items-center gap-2 text-gray-400">
                <Search className="size-6" strokeWidth={1.5} />
                <p className={`${font} text-[13px]`}>{t("admin_perm_no_results") || "ไม่พบรายการสิทธิที่ตรงกับการค้นหา"}</p>
              </div>
            ) : (
              <div className="divide-y divide-gray-100">
                {Object.entries(groupedByCategory).map(([category, perms]) => (
                  <div key={category}>
                    <div className="px-4 sm:px-5 py-2 bg-gray-50/60">
                      <p className={`${font} text-[11px] text-gray-500 uppercase tracking-wide`} style={{ fontWeight: 600 }}>{category}</p>
                    </div>
                    <ul className="divide-y divide-gray-50">
                      {perms.map((p) => {
                        const checked = g.permissions.includes(p.id);
                        return (
                          <li key={p.id}
                            className="px-4 sm:px-5 py-3 flex items-center gap-3 hover:bg-gray-50/40 transition-colors cursor-pointer"
                            onClick={() => togglePermInDraft(p.id)}>
                            <div className="flex-1 min-w-0">
                              <p className={`${font} text-[13px] text-black`} style={{ fontWeight: 500 }}>{p.label}</p>
                              {p.desc && <p className={`${font} text-[11px] text-gray-500 mt-0.5`}>{p.desc}</p>}
                            </div>
                            <PermToggle checked={checked} onChange={() => togglePermInDraft(p.id)} color="#319754" />
                          </li>
                        );
                      })}
                    </ul>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>

        <Dialog open={confirm !== null} onOpenChange={(v) => !v && setConfirm(null)}>
          <DialogContent className="max-w-[400px]">
            <DialogHeader>
              <DialogTitle className={`${font}`} style={{ fontWeight: 600 }}>
                {t("admin_perm_confirm_del_group") || "ลบกลุ่มสิทธิ?"}
              </DialogTitle>
              <DialogDescription className={`${font} text-[12px]`}>
                {t("admin_perm_confirm_desc") || "การลบจะมีผลทันทีและไม่สามารถย้อนกลับได้"} — <span style={{ fontWeight: 600 }}>{confirm?.label}</span>
              </DialogDescription>
            </DialogHeader>
            <DialogFooter>
              <button onClick={() => setConfirm(null)}
                className={`${font} h-10 px-4 rounded-full bg-gray-100 hover:bg-gray-200 text-gray-700 text-[13px] cursor-pointer`}
                style={{ fontWeight: 500 }}>
                {t("admin_perm_cancel") || "ยกเลิก"}
              </button>
              <button onClick={() => {
                if (!confirm) return;
                deleteGroup(confirm.id);
                setConfirm(null);
              }}
                className={`${font} h-10 px-5 rounded-full bg-[#ff3b30] hover:bg-[#dc2626] text-white text-[13px] cursor-pointer`}
                style={{ fontWeight: 600 }}>
                {t("admin_perm_confirm_delete") || "ยืนยันการลบ"}
              </button>
            </DialogFooter>
          </DialogContent>
        </Dialog>
      </div>
    );
  }

  /* ============== LIST VIEW ============== */
  return (
    <div>
      {/* Header — same pattern as other admin pages */}
      <div className="flex items-center justify-between mb-6 flex-wrap gap-3">
        <div>
          <h2 className={`${font} text-[22px]`} style={{ fontWeight: 600 }}>{t("admin_perm_title") || "การกำหนดสิทธิ"}</h2>
          <p className={`${font} text-[13px] text-gray-500 mt-0.5`}>{t("admin_perm_subtitle") || "กำหนดสิทธิ์การเข้าถึงสำหรับแต่ละบทบาท"}</p>
        </div>
        <motion.button whileTap={{ scale: 0.96 }} whileHover={{ scale: 1.03 }}
          onClick={openAdd}
          className={`${font} inline-flex items-center gap-2 text-[13px] text-white px-5 h-[36px] rounded-full transition-colors shadow-[0_2px_8px_rgba(49,151,84,0.25)] cursor-pointer`}
          style={{ backgroundColor: ADMIN_PRIMARY, fontWeight: 500 }}>
          <Plus className="size-4" strokeWidth={2.4} />
          {t("admin_perm_add_group") || "เพิ่มกลุ่มสิทธิ"}
        </motion.button>
      </div>

      {/* Group cards */}
      {groups.length === 0 ? (
        <div className="bg-white rounded-2xl shadow-[0_1px_4px_rgba(0,0,0,0.04)] p-10 flex flex-col items-center gap-3 text-gray-400">
          <Folder className="size-8" strokeWidth={1.5} />
          <p className={`${font} text-[13px]`}>{t("admin_perm_no_groups") || "ยังไม่มีกลุ่มสิทธิ"}</p>
          <button onClick={openAdd}
            className={`${font} inline-flex items-center gap-1.5 h-9 px-4 rounded-full bg-[#319754] hover:bg-[#287745] text-white text-[12px] cursor-pointer`}
            style={{ fontWeight: 600 }}>
            <Plus className="size-3.5" strokeWidth={2.4} />
            {t("admin_perm_add_first_group") || "สร้างกลุ่มแรก"}
          </button>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
          {groups.map((g) => {
            const GIcon = g.icon;
            const disabled = !g.enabled;
            return (
              <motion.div key={g.id}
                whileHover={{ y: -2 }}
                transition={{ type: "spring", stiffness: 320, damping: 24 }}
                className={`bg-white rounded-2xl shadow-[0_1px_4px_rgba(0,0,0,0.04)] hover:shadow-[0_4px_16px_rgba(0,0,0,0.08)] transition-shadow overflow-hidden flex flex-col ${disabled ? "opacity-60" : ""}`}>
                <div className="p-4 sm:p-5 flex items-start gap-3">
                  <button onClick={() => openEditor(g.id)}
                    className="size-11 rounded-xl flex items-center justify-center shrink-0 cursor-pointer hover:scale-105 transition-transform"
                    style={{ backgroundColor: `${g.iconColor}1a` }}>
                    <GIcon className="size-5" style={{ color: g.iconColor }} strokeWidth={2.2} />
                  </button>
                  <button onClick={() => openEditor(g.id)}
                    className="min-w-0 flex-1 text-left cursor-pointer">
                    <div className="flex items-center gap-2 flex-wrap">
                      <p className={`${font} text-[15px] text-black`} style={{ fontWeight: 600 }}>{g.label || "—"}</p>
                      {disabled && (
                        <span className={`${font} inline-flex items-center gap-1 text-[10px] px-2 py-0.5 rounded-full bg-gray-200 text-gray-600`} style={{ fontWeight: 600 }}>
                          <EyeOff className="size-2.5" strokeWidth={2.4} />
                          {t("admin_perm_disabled") || "ปิดใช้งาน"}
                        </span>
                      )}
                    </div>
                    <p className={`${font} text-[12px] text-gray-500 mt-0.5 line-clamp-2`}>{g.desc || "—"}</p>
                    <span className={`${font} inline-flex items-center gap-1 text-[11px] px-2 py-1 rounded-full bg-gray-100 text-gray-700 mt-2`} style={{ fontWeight: 500 }}>
                      <ShieldCheck className="size-3" strokeWidth={2.4} />
                      {g.permissions.length}/{ALL_PERMISSIONS.length} {t("admin_perm_count_unit") || "สิทธิ"}
                    </span>
                  </button>

                  {/* More button → popover */}
                  <Popover>
                    <PopoverTrigger asChild>
                      <button title={t("admin_perm_more") || "เพิ่มเติม"}
                        onClick={(e) => e.stopPropagation()}
                        className="size-8 rounded-lg hover:bg-gray-100 flex items-center justify-center cursor-pointer shrink-0">
                        <MoreHorizontal className="size-4 text-gray-500" strokeWidth={2.4} />
                      </button>
                    </PopoverTrigger>
                    <PopoverContent align="end" sideOffset={6} className="w-56 p-1.5">
                      <div className="flex items-center justify-between gap-2 px-2.5 py-2 rounded-md">
                        <div className="flex items-center gap-2 min-w-0">
                          {g.enabled
                            ? <Eye className="size-3.5 text-[#319754]" strokeWidth={2.4} />
                            : <EyeOff className="size-3.5 text-gray-400" strokeWidth={2.4} />}
                          <span className={`${font} text-[13px] text-black`} style={{ fontWeight: 500 }}>
                            {g.enabled ? (t("admin_perm_enabled") || "เปิดใช้งาน") : (t("admin_perm_disabled") || "ปิดใช้งาน")}
                          </span>
                        </div>
                        <PermToggle checked={g.enabled} onChange={() => toggleGroupEnabled(g.id)} color="#319754" />
                      </div>
                      <div className="h-px bg-gray-100 my-1" />
                      <button onClick={() => openEditor(g.id)}
                        className={`${font} w-full flex items-center gap-2 px-2.5 py-2 rounded-md hover:bg-gray-50 cursor-pointer text-left`}>
                        <Pencil className="size-3.5 text-gray-500" strokeWidth={2.4} />
                        <span className="text-[13px] text-black" style={{ fontWeight: 500 }}>{t("admin_perm_edit_group") || "แก้ไขกลุ่ม"}</span>
                      </button>
                      <button onClick={() => setConfirm({ kind: "group", id: g.id, label: g.label })}
                        className={`${font} w-full flex items-center gap-2 px-2.5 py-2 rounded-md hover:bg-[#ff3b30]/10 cursor-pointer text-left`}>
                        <Trash2 className="size-3.5 text-[#ff3b30]" strokeWidth={2.4} />
                        <span className="text-[13px] text-[#dc2626]" style={{ fontWeight: 500 }}>{t("admin_perm_delete_group") || "ลบกลุ่ม"}</span>
                      </button>
                    </PopoverContent>
                  </Popover>
                </div>
              </motion.div>
            );
          })}
        </div>
      )}

      <Dialog open={confirm !== null} onOpenChange={(v) => !v && setConfirm(null)}>
        <DialogContent className="max-w-[400px]">
          <DialogHeader>
            <DialogTitle className={`${font}`} style={{ fontWeight: 600 }}>
              {t("admin_perm_confirm_del_group") || "ลบกลุ่มสิทธิ?"}
            </DialogTitle>
            <DialogDescription className={`${font} text-[12px]`}>
              {t("admin_perm_confirm_desc") || "การลบจะมีผลทันทีและไม่สามารถย้อนกลับได้"} — <span style={{ fontWeight: 600 }}>{confirm?.label}</span>
            </DialogDescription>
          </DialogHeader>
          <DialogFooter>
            <button onClick={() => setConfirm(null)}
              className={`${font} h-10 px-4 rounded-full bg-gray-100 hover:bg-gray-200 text-gray-700 text-[13px] cursor-pointer`}
              style={{ fontWeight: 500 }}>
              {t("admin_perm_cancel") || "ยกเลิก"}
            </button>
            <button onClick={() => {
              if (!confirm) return;
              if (confirm.kind === "group") deleteGroup(confirm.id);
              setConfirm(null);
            }}
              className={`${font} h-10 px-5 rounded-full bg-[#ff3b30] hover:bg-[#dc2626] text-white text-[13px] cursor-pointer`}
              style={{ fontWeight: 600 }}>
              {t("admin_perm_confirm_delete") || "ยืนยันการลบ"}
            </button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

/* ============================================================
 * ADMIN NOTIFICATION SETTINGS PAGE
 * ========================================================== */
type NotifChannel = "email" | "push" | "sms" | "inapp";

interface NotifEventConfig {
  enabled: boolean;
  channels: NotifChannel[];
  threshold?: number;
}

interface NotifMeta {
  id: string;
  category: "registry" | "orders" | "system" | "content";
  icon: any;
  iconColor: string;
  label: string;
  desc: string;
  thresholdLabel?: string;
  thresholdSuffix?: string;
}

const NOTIF_EVENTS: NotifMeta[] = [
  { id: "shop_pending",    category: "registry", icon: Store,         iconColor: "#319754", label: "ร้านค้าใหม่ลงทะเบียน",       desc: "ร้านที่รออนุมัติ — แอดมินตรวจและกดอนุมัติ" },
  { id: "user_signup",     category: "registry", icon: Users,         iconColor: "#3b82f6", label: "ผู้ใช้ใหม่สมัครสมาชิก",       desc: "ลูกค้า / เจ้าของร้าน สมัครเข้าสู่ระบบ" },
  { id: "user_reported",   category: "registry", icon: AlertCircle,   iconColor: "#ff3b30", label: "ผู้ใช้ / ร้านค้าถูกรายงาน", desc: "มีคนรายงานพฤติกรรมไม่เหมาะสม" },

  { id: "large_order",     category: "orders",   icon: ShoppingCart,  iconColor: "#9747ff", label: "ออเดอร์มูลค่าสูง",            desc: "แจ้งเตือนเมื่อมีออเดอร์เกินเกณฑ์", thresholdLabel: "มูลค่าขั้นต่ำ", thresholdSuffix: "บาท" },
  { id: "complaint_new",   category: "orders",   icon: AlertCircle,   iconColor: "#f59e0b", label: "การร้องเรียนใหม่",             desc: "ลูกค้าร้องเรียนเกี่ยวกับสินค้า / ร้าน" },
  { id: "refund_request",  category: "orders",   icon: DollarSign,    iconColor: "#f59e0b", label: "คำขอคืนเงิน",                   desc: "ลูกค้าขอคืนเงิน — รออนุมัติ" },
  { id: "payment_failed",  category: "orders",   icon: X,             iconColor: "#ff3b30", label: "การชำระเงินล้มเหลว",         desc: "ออเดอร์มีปัญหาการชำระเงิน" },
  { id: "withdrawal",      category: "orders",   icon: DollarSign,    iconColor: "#287745", label: "การถอนเงินจากร้านค้า",      desc: "ร้านขอถอนเงินมูลค่าสูง", thresholdLabel: "มูลค่าขั้นต่ำ", thresholdSuffix: "บาท" },

  { id: "system_error",    category: "system",   icon: AlertCircle,   iconColor: "#ff3b30", label: "Error rate สูง / ระบบมีปัญหา", desc: "เกิดข้อผิดพลาดในระบบเกินเกณฑ์ปกติ" },
  { id: "failed_logins",   category: "system",   icon: Shield,        iconColor: "#f59e0b", label: "ล็อกอินล้มเหลวซ้ำ",         desc: "มีการลองเข้าระบบล้มเหลวจำนวนมาก — สงสัย attack" },
  { id: "admin_login_new", category: "system",   icon: UserCog,       iconColor: "#9747ff", label: "แอดมินเข้าระบบจาก IP ใหม่",  desc: "บัญชีแอดมินถูกใช้จากอุปกรณ์ / ตำแหน่งใหม่" },
  { id: "suspicious",      category: "system",   icon: Shield,        iconColor: "#ff3b30", label: "กิจกรรมน่าสงสัย",             desc: "ระบบตรวจพบพฤติกรรมผิดปกติ" },

  { id: "review_reported", category: "content",  icon: Star,          iconColor: "#f59e0b", label: "รีวิวที่ถูกรายงาน",            desc: "ลูกค้ารายงานรีวิวว่าไม่เหมาะสม / spam" },
  { id: "product_reported",category: "content",  icon: Package,       iconColor: "#9747ff", label: "สินค้าที่ถูกรายงาน",          desc: "ลูกค้ารายงานสินค้าว่าน่าสงสัย / ของปลอม" },
  { id: "banned_content",  category: "content",  icon: MessageSquare, iconColor: "#ff3b30", label: "คอมเมนต์ต้องห้าม (Auto)",     desc: "ระบบตรวจพบคำต้องห้าม / spam อัตโนมัติ" },
];

interface AdminNotifConfig {
  channels: {
    email: { enabled: boolean; address: string };
    push:  { enabled: boolean };
    sms:   { enabled: boolean; phone: string };
  };
  events: Record<string, NotifEventConfig>;
  reports: {
    daily:   { enabled: boolean; time: string };
    weekly:  { enabled: boolean; day: number };
    monthly: { enabled: boolean; date: number };
  };
}

const DEFAULT_NOTIF_CONFIG: AdminNotifConfig = {
  channels: {
    email: { enabled: true,  address: "admin@metaherb.co.th" },
    push:  { enabled: true },
    sms:   { enabled: false, phone: "" },
  },
  events: Object.fromEntries(NOTIF_EVENTS.map(e => [e.id, {
    enabled: ["shop_pending", "complaint_new", "payment_failed", "system_error", "failed_logins", "admin_login_new", "suspicious"].includes(e.id),
    channels: ["email", "inapp"] as NotifChannel[],
    threshold: e.id === "large_order" ? 50000 : e.id === "withdrawal" ? 100000 : undefined,
  }])),
  reports: {
    daily:   { enabled: true,  time: "09:00" },
    weekly:  { enabled: true,  day: 1 },  // จันทร์
    monthly: { enabled: false, date: 1 },
  },
};

const CHANNEL_META: Record<NotifChannel, { label: string; icon: any; color: string }> = {
  email: { label: "Email",  icon: Mail,         color: "#3b82f6" },
  push:  { label: "Push",   icon: Bell,         color: "#319754" },
  sms:   { label: "SMS",    icon: MessageSquare, color: "#9747ff" },
  inapp: { label: "In-app", icon: Shield,       color: "#6b7280" },
};

function ChannelChip({ channel, active, disabled, onClick }: {
  channel: NotifChannel; active: boolean; disabled?: boolean; onClick: () => void;
}) {
  const meta = CHANNEL_META[channel];
  return (
    <button onClick={onClick} disabled={disabled}
      className={`${font} inline-flex items-center gap-1 h-7 px-2.5 rounded-full text-[11px] transition-all ${
        disabled ? "opacity-40 cursor-not-allowed bg-gray-100 text-gray-400" :
        active   ? "cursor-pointer text-white" : "cursor-pointer bg-gray-100 text-gray-600 hover:bg-gray-200"
      }`}
      style={active && !disabled ? { backgroundColor: meta.color, fontWeight: 500 } : { fontWeight: 500 }}
      title={disabled ? `ปิดที่ช่องทาง ${meta.label} ในด้านบน` : undefined}>
      <meta.icon className="size-3" strokeWidth={2.4} />
      {meta.label}
    </button>
  );
}

function NotifEventRow({ meta, config, channelGlobal, onToggle, onToggleChannel, onThreshold }: {
  meta: NotifMeta;
  config: NotifEventConfig;
  channelGlobal: AdminNotifConfig["channels"];
  onToggle: () => void;
  onToggleChannel: (ch: NotifChannel) => void;
  onThreshold: (v: number) => void;
}) {
  return (
    <div className="rounded-xl border border-gray-200 p-3">
      <div className="flex items-start justify-between gap-3">
        <div className="flex items-start gap-2.5 min-w-0 flex-1">
          <div className="size-9 rounded-lg flex items-center justify-center shrink-0" style={{ backgroundColor: `${meta.iconColor}15` }}>
            <meta.icon className="size-4" style={{ color: meta.iconColor }} strokeWidth={2.2} />
          </div>
          <div className="min-w-0 flex-1">
            <p className={`${font} text-[13px] text-black`} style={{ fontWeight: 500 }}>{meta.label}</p>
            <p className={`${font} text-[11px] text-gray-500 mt-0.5 leading-snug`}>{meta.desc}</p>
          </div>
        </div>
        <ToggleSwitch checked={config.enabled} onChange={onToggle} />
      </div>
      {config.enabled && (
        <div className="mt-3 pt-3 border-t border-gray-100 flex flex-wrap items-center gap-3">
          <div className="flex items-center gap-1.5 flex-wrap">
            <span className={`${font} text-[10px] uppercase tracking-wide text-gray-400`} style={{ fontWeight: 600 }}>ช่องทาง</span>
            {(["email", "push", "sms", "inapp"] as NotifChannel[]).map((ch) => {
              const inactive = ch !== "inapp" && !channelGlobal[ch].enabled;
              return (
                <ChannelChip key={ch} channel={ch}
                  active={config.channels.includes(ch)}
                  disabled={inactive}
                  onClick={() => onToggleChannel(ch)} />
              );
            })}
          </div>
          {meta.thresholdLabel && (
            <div className="flex items-center gap-2 ml-auto">
              <label className={`${font} text-[11px] text-gray-500`}>{meta.thresholdLabel}</label>
              <div className="relative">
                <input type="number" value={config.threshold ?? 0}
                  onChange={(e) => onThreshold(Number(e.target.value) || 0)}
                  className={`${font} h-8 px-2.5 pr-12 w-[140px] rounded-md border border-gray-200 text-[12px] focus:outline-none focus:border-[#319754] focus:ring-2 focus:ring-[#319754]/10 bg-white tabular-nums transition-all`} />
                <span className={`${font} absolute right-2.5 top-1/2 -translate-y-1/2 text-[11px] text-gray-400 pointer-events-none`}>{meta.thresholdSuffix}</span>
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

function SettingsNotificationsPage() {
  const [cfg, setCfg] = useState<AdminNotifConfig>(DEFAULT_NOTIF_CONFIG);
  const isDirty = JSON.stringify(cfg) !== JSON.stringify(DEFAULT_NOTIF_CONFIG);

  const updEventEnabled = (id: string) => setCfg(prev => ({
    ...prev, events: { ...prev.events, [id]: { ...prev.events[id], enabled: !prev.events[id].enabled } },
  }));
  const updEventChannel = (id: string, ch: NotifChannel) => setCfg(prev => {
    const current = prev.events[id].channels;
    const next = current.includes(ch) ? current.filter(c => c !== ch) : [...current, ch];
    return { ...prev, events: { ...prev.events, [id]: { ...prev.events[id], channels: next } } };
  });
  const updEventThreshold = (id: string, v: number) => setCfg(prev => ({
    ...prev, events: { ...prev.events, [id]: { ...prev.events[id], threshold: v } },
  }));

  const eventsByCategory = (cat: NotifMeta["category"]) => NOTIF_EVENTS.filter(e => e.category === cat);
  const renderEvents = (cat: NotifMeta["category"]) => (
    <div className="flex flex-col gap-2.5">
      {eventsByCategory(cat).map((e) => (
        <NotifEventRow key={e.id} meta={e}
          config={cfg.events[e.id]}
          channelGlobal={cfg.channels}
          onToggle={() => updEventEnabled(e.id)}
          onToggleChannel={(ch) => updEventChannel(e.id, ch)}
          onThreshold={(v) => updEventThreshold(e.id, v)} />
      ))}
    </div>
  );

  const dayNames = ["อาทิตย์", "จันทร์", "อังคาร", "พุธ", "พฤหัสบดี", "ศุกร์", "เสาร์"];

  return (
    <div className="flex flex-col gap-5 pb-2">
      {/* 1. Channels */}
      <SettingsCard icon={Bell} title="ช่องทางการแจ้งเตือน" desc="เปิด/ปิด ช่องทางหลักที่ระบบจะใช้ส่งแจ้งเตือนให้แอดมิน">
        <div className="flex flex-col gap-3">
          {/* Email */}
          <div className="rounded-xl border border-gray-200 p-3 flex items-center gap-3 flex-wrap">
            <div className="size-9 rounded-lg bg-[#3b82f6]/10 flex items-center justify-center shrink-0">
              <Mail className="size-4 text-[#3b82f6]" strokeWidth={2.2} />
            </div>
            <div className="flex-1 min-w-[200px]">
              <p className={`${font} text-[13px] text-black`} style={{ fontWeight: 500 }}>Email</p>
              <p className={`${font} text-[11px] text-gray-500`}>ส่งสรุปและแจ้งเตือนสำคัญทางอีเมล</p>
            </div>
            {cfg.channels.email.enabled && (
              <input type="email" value={cfg.channels.email.address}
                onChange={(e) => setCfg(prev => ({ ...prev, channels: { ...prev.channels, email: { ...prev.channels.email, address: e.target.value } } }))}
                placeholder="admin@example.com"
                className={`${font} h-9 px-3 w-full sm:w-[260px] rounded-md border border-gray-200 text-[12px] focus:outline-none focus:border-[#319754] focus:ring-2 focus:ring-[#319754]/10 bg-white transition-all`} />
            )}
            <ToggleSwitch checked={cfg.channels.email.enabled}
              onChange={() => setCfg(prev => ({ ...prev, channels: { ...prev.channels, email: { ...prev.channels.email, enabled: !prev.channels.email.enabled } } }))} />
          </div>

          {/* Push */}
          <div className="rounded-xl border border-gray-200 p-3 flex items-center gap-3">
            <div className="size-9 rounded-lg bg-[#319754]/10 flex items-center justify-center shrink-0">
              <Bell className="size-4 text-[#319754]" strokeWidth={2.2} />
            </div>
            <div className="flex-1 min-w-0">
              <p className={`${font} text-[13px] text-black`} style={{ fontWeight: 500 }}>Push Notification (Web)</p>
              <p className={`${font} text-[11px] text-gray-500`}>แจ้งเตือนแบบ pop-up เมื่อแอดมินออนไลน์อยู่</p>
            </div>
            <ToggleSwitch checked={cfg.channels.push.enabled}
              onChange={() => setCfg(prev => ({ ...prev, channels: { ...prev.channels, push: { enabled: !prev.channels.push.enabled } } }))} />
          </div>

          {/* SMS */}
          <div className="rounded-xl border border-gray-200 p-3 flex items-center gap-3 flex-wrap">
            <div className="size-9 rounded-lg bg-[#9747ff]/10 flex items-center justify-center shrink-0">
              <MessageSquare className="size-4 text-[#9747ff]" strokeWidth={2.2} />
            </div>
            <div className="flex-1 min-w-[200px]">
              <p className={`${font} text-[13px] text-black`} style={{ fontWeight: 500 }}>SMS</p>
              <p className={`${font} text-[11px] text-gray-500`}>เฉพาะเหตุการณ์เร่งด่วน — มีค่าใช้จ่ายต่อข้อความ</p>
            </div>
            {cfg.channels.sms.enabled && (
              <input type="tel" value={cfg.channels.sms.phone}
                onChange={(e) => setCfg(prev => ({ ...prev, channels: { ...prev.channels, sms: { ...prev.channels.sms, phone: e.target.value } } }))}
                placeholder="0X-XXXX-XXXX"
                className={`${font} h-9 px-3 w-full sm:w-[220px] rounded-md border border-gray-200 text-[12px] focus:outline-none focus:border-[#319754] focus:ring-2 focus:ring-[#319754]/10 bg-white transition-all`} />
            )}
            <ToggleSwitch checked={cfg.channels.sms.enabled}
              onChange={() => setCfg(prev => ({ ...prev, channels: { ...prev.channels, sms: { ...prev.channels.sms, enabled: !prev.channels.sms.enabled } } }))} />
          </div>

          {/* In-app — always on */}
          <div className="rounded-xl border border-gray-100 bg-gray-50/50 p-3 flex items-center gap-3">
            <div className="size-9 rounded-lg bg-gray-200 flex items-center justify-center shrink-0">
              <Shield className="size-4 text-gray-500" strokeWidth={2.2} />
            </div>
            <div className="flex-1 min-w-0">
              <p className={`${font} text-[13px] text-gray-700`} style={{ fontWeight: 500 }}>In-app (ในระบบ)</p>
              <p className={`${font} text-[11px] text-gray-400`}>แสดงในไอคอนกระดิ่ง — เปิดอยู่เสมอ ปิดไม่ได้</p>
            </div>
            <span className={`${font} text-[11px] bg-[#319754]/10 text-[#287745] px-2.5 py-1 rounded-full`} style={{ fontWeight: 600 }}>เปิดอยู่</span>
          </div>
        </div>
      </SettingsCard>

      {/* 2. Registry */}
      <SettingsCard icon={UserCog} title="ทะเบียนผู้ใช้และร้านค้า" desc="กิจกรรมที่เกี่ยวกับการสมัคร / อนุมัติ / การรายงาน">
        {renderEvents("registry")}
      </SettingsCard>

      {/* 3. Orders & Finance */}
      <SettingsCard icon={ShoppingCart} title="คำสั่งซื้อและการเงิน" desc="การทำธุรกรรม / การร้องเรียน / การชำระเงิน">
        {renderEvents("orders")}
      </SettingsCard>

      {/* 4. System & Security */}
      <SettingsCard icon={Shield} title="ระบบและความปลอดภัย" desc="สุขภาพของระบบและการเข้าใช้งานที่น่าสงสัย">
        {renderEvents("system")}
      </SettingsCard>

      {/* 5. Content Moderation */}
      <SettingsCard icon={MessageSquare} title="คอนเทนต์และการกลั่นกรอง" desc="รีวิว / สินค้า / คอมเมนต์ที่ต้องตรวจสอบ">
        {renderEvents("content")}
      </SettingsCard>

      {/* 6. Reports */}
      <SettingsCard icon={FileText} title="รายงานสรุป" desc="รับสรุปข้อมูลของแพลตฟอร์มทุกช่วงเวลา">
        <div className="flex flex-col gap-2.5">
          {/* Daily */}
          <div className="rounded-xl border border-gray-200 p-3">
            <div className="flex items-center justify-between gap-3">
              <div className="flex items-center gap-2.5 min-w-0">
                <div className="size-9 rounded-lg bg-[#319754]/10 flex items-center justify-center shrink-0">
                  <Clock className="size-4 text-[#319754]" strokeWidth={2.2} />
                </div>
                <div className="min-w-0">
                  <p className={`${font} text-[13px] text-black`} style={{ fontWeight: 500 }}>รายงานรายวัน</p>
                  <p className={`${font} text-[11px] text-gray-500`}>สรุปยอดขาย / ออเดอร์ / ลูกค้าใหม่ของวันก่อนหน้า</p>
                </div>
              </div>
              <ToggleSwitch checked={cfg.reports.daily.enabled}
                onChange={() => setCfg(prev => ({ ...prev, reports: { ...prev.reports, daily: { ...prev.reports.daily, enabled: !prev.reports.daily.enabled } } }))} />
            </div>
            {cfg.reports.daily.enabled && (
              <div className="mt-3 pt-3 border-t border-gray-100 flex items-center gap-2">
                <label className={`${font} text-[11px] text-gray-500`}>ส่งทุกวันเวลา</label>
                <input type="time" value={cfg.reports.daily.time}
                  onChange={(e) => setCfg(prev => ({ ...prev, reports: { ...prev.reports, daily: { ...prev.reports.daily, time: e.target.value } } }))}
                  className={`${font} h-8 px-2.5 w-[110px] rounded-md border border-gray-200 text-[12px] focus:outline-none focus:border-[#319754] focus:ring-2 focus:ring-[#319754]/10 bg-white transition-all`} />
                <span className={`${font} text-[11px] text-gray-400`}>น.</span>
              </div>
            )}
          </div>

          {/* Weekly */}
          <div className="rounded-xl border border-gray-200 p-3">
            <div className="flex items-center justify-between gap-3">
              <div className="flex items-center gap-2.5 min-w-0">
                <div className="size-9 rounded-lg bg-[#3b82f6]/10 flex items-center justify-center shrink-0">
                  <Clock className="size-4 text-[#3b82f6]" strokeWidth={2.2} />
                </div>
                <div className="min-w-0">
                  <p className={`${font} text-[13px] text-black`} style={{ fontWeight: 500 }}>รายงานรายสัปดาห์</p>
                  <p className={`${font} text-[11px] text-gray-500`}>สรุปประสิทธิภาพและแนวโน้มในสัปดาห์ที่ผ่านมา</p>
                </div>
              </div>
              <ToggleSwitch checked={cfg.reports.weekly.enabled}
                onChange={() => setCfg(prev => ({ ...prev, reports: { ...prev.reports, weekly: { ...prev.reports.weekly, enabled: !prev.reports.weekly.enabled } } }))} />
            </div>
            {cfg.reports.weekly.enabled && (
              <div className="mt-3 pt-3 border-t border-gray-100 flex items-center gap-2 flex-wrap">
                <label className={`${font} text-[11px] text-gray-500`}>ส่งทุกวัน</label>
                <div className="inline-flex bg-gray-100 rounded-full p-0.5">
                  {dayNames.map((d, i) => {
                    const active = cfg.reports.weekly.day === i;
                    return (
                      <button key={i} onClick={() => setCfg(prev => ({ ...prev, reports: { ...prev.reports, weekly: { ...prev.reports.weekly, day: i } } }))}
                        className={`${font} h-7 px-2.5 rounded-full text-[11px] cursor-pointer transition-all ${active ? "bg-white shadow-sm text-[#319754]" : "text-gray-500 hover:text-black"}`}
                        style={{ fontWeight: active ? 600 : 500 }}>
                        {d}
                      </button>
                    );
                  })}
                </div>
              </div>
            )}
          </div>

          {/* Monthly */}
          <div className="rounded-xl border border-gray-200 p-3">
            <div className="flex items-center justify-between gap-3">
              <div className="flex items-center gap-2.5 min-w-0">
                <div className="size-9 rounded-lg bg-[#9747ff]/10 flex items-center justify-center shrink-0">
                  <Clock className="size-4 text-[#9747ff]" strokeWidth={2.2} />
                </div>
                <div className="min-w-0">
                  <p className={`${font} text-[13px] text-black`} style={{ fontWeight: 500 }}>รายงานรายเดือน</p>
                  <p className={`${font} text-[11px] text-gray-500`}>สรุปรายได้ / KPI ของเดือนที่ผ่านมา</p>
                </div>
              </div>
              <ToggleSwitch checked={cfg.reports.monthly.enabled}
                onChange={() => setCfg(prev => ({ ...prev, reports: { ...prev.reports, monthly: { ...prev.reports.monthly, enabled: !prev.reports.monthly.enabled } } }))} />
            </div>
            {cfg.reports.monthly.enabled && (
              <div className="mt-3 pt-3 border-t border-gray-100 flex items-center gap-2">
                <label className={`${font} text-[11px] text-gray-500`}>ส่งทุกวันที่</label>
                <input type="number" min={1} max={28} value={cfg.reports.monthly.date}
                  onChange={(e) => setCfg(prev => ({ ...prev, reports: { ...prev.reports, monthly: { ...prev.reports.monthly, date: Math.min(28, Math.max(1, Number(e.target.value) || 1)) } } }))}
                  className={`${font} h-8 px-2.5 w-[80px] rounded-md border border-gray-200 text-[12px] focus:outline-none focus:border-[#319754] focus:ring-2 focus:ring-[#319754]/10 bg-white tabular-nums transition-all`} />
                <span className={`${font} text-[11px] text-gray-400`}>ของเดือน (1-28)</span>
              </div>
            )}
          </div>
        </div>
        <SaveBar isDirty={isDirty}
          onReset={() => setCfg(DEFAULT_NOTIF_CONFIG)}
          onSave={() => toast.success("บันทึกตั้งค่าแจ้งเตือนเรียบร้อย")} />
      </SettingsCard>
    </div>
  );
}

/* ========== Admin Promotions ========== */
type AdminPromoStatus = "active" | "scheduled" | "ended";
type AdminPromoDiscountType = "percent" | "baht";
type ShopInviteStatus = "pending" | "accepted" | "declined";

interface AdminPromoInvite { shopName: string; status: ShopInviteStatus; respondedAt?: string }

// Shop profile images — keyed by shopName (matches siteProducts.shopName values)
const SHOP_PROFILE_IMAGES: Record<string, string> = {
  "METAHERB Store":     "https://images.unsplash.com/photo-1620916566398-39f1143ab7be?w=200&q=80", // green herb shop
  "Organic Thai Farm":  "https://images.unsplash.com/photo-1500382017468-9049fed747ef?w=200&q=80", // farm field
  "ธรรมชาติพรีเมียม":    "https://images.unsplash.com/photo-1543362906-acfc16c67564?w=200&q=80",   // premium nature
  "ร้านป่าหมอก":         "https://images.unsplash.com/photo-1441974231531-c6227db76b6e?w=200&q=80", // misty forest
  "สมุนไพรบ้านสวน":      "https://images.unsplash.com/photo-1466692476868-aef1dfb1e735?w=200&q=80", // garden
};
const getShopImage = (name: string) => SHOP_PROFILE_IMAGES[name] || "";

// Promotion themes — holidays, festivals, or trending campaigns (long-running, unlike Flash Sale's date-numeric events)
type PromoTheme = "valentine" | "songkran" | "mother" | "father" | "christmas" | "newyear" | "loykrathong" | "wellness" | "earth";
